export const studioDocs = {
  init:       { sig: 'void init()',                                                    doc: 'Called once after the window opens, before the first update(). Optional.\nUse for one-time setup: colorkey(), building the map, seeding state.\nAvoid the static bool workaround — this is the right place.' },
  update:     { sig: 'void update()',                                                  doc: 'Called every frame. Move things, read input. Optional.' },
  draw:       { sig: 'void draw()',                                                    doc: 'Called every frame after update. Draw things.' },
  de_players: { sig: 'int de_players()',                                               doc: 'Optional. Return how many players your cart supports (default 1 = solo).\nReturn 2 to enable the MULTIPLAYER pause-menu item + Host/Join/Solo lobby (lockstep netplay).\nExample:  int de_players(void) { return 2; }' },
  btn:        { sig: 'bool btn(int player, int button)',                               doc: 'Returns true while the button is held.\nplayer: 0 (Arrows+Z/X) or 1 (WASD+J/K) by default — rebind per player in settings → controls.\nWhen on-screen controls are enabled, player 0 also reads the floating stick and A/B touch buttons.' },
  btnp:       { sig: 'bool btnp(int player, int button)',                              doc: 'Returns true only on the frame the button was pressed (edge-triggered).\nUse this to fire sfx() on a press without retriggering every frame.' },
  btnr:       { sig: 'bool btnr(int player, int button)',                              doc: 'Returns true only on the frame the button was released (the falling edge).\nPair with btnp() for press/release gestures — e.g. note_on() on btnp, note_off() on btnr.' },
  touch_count:    { sig: 'int touch_count()',                                          doc: 'Number of fingers currently down (0..10). On desktop, mouse LMB counts as one touch.' },
  touch_x:        { sig: 'int touch_x(int i)',                                         doc: 'X position of touch i in canvas coordinates. Returns -1 if i is out of range.\nOn desktop, mouse LMB shows up as a touch.' },
  touch_y:        { sig: 'int touch_y(int i)',                                         doc: 'Y position of touch i in canvas coordinates. Returns -1 if i is out of range.\nOn desktop, mouse LMB shows up as a touch.' },
  touch_id:       { sig: 'int touch_id(int i)',                                        doc: 'Stable id of touch i, or -1 if i is out of range. Indices shuffle when a finger lifts; the id follows the same finger from touchdown to release.\nUse it to track fingers across frames (multi-finger piano, pinch). The desktop mouse-touch has id -2.\nif (touch_id(i) == held_id) { ... }' },
  tap:            { sig: 'bool tap(int x, int y, int w, int h)',                       doc: 'True if any finger is inside this rectangle (canvas-space).\nOn desktop, mouse clicks register as taps.' },
  tapp:           { sig: 'bool tapp(int x, int y, int w, int h)',                      doc: 'True only on the frame a touch BEGAN inside this rectangle (edge-triggered, like btnp vs btn).\nUse for buttons so one tap fires once, not 60×/sec.\nif (tapp(bx, by, 32, 16)) toggle();' },
  touch_ended_count: { sig: 'int touch_ended_count()',                              doc: 'How many fingers LIFTED since last frame. A released finger has no touch_x index anymore — this list is the only way to see it.\nLoop it for note-offs, drop events, swipe ends.\nfor (int i = 0; i < touch_ended_count(); i++) { ... }' },
  touch_ended_id: { sig: 'int touch_ended_id(int i)',                                doc: 'Stable id of lifted finger i, or -1 if i is out of range. Pair it with the id you tracked while the finger was down to know WHICH finger left.\nif (touch_ended_id(i) == key_finger[k]) note_off(k);' },
  touch_ended_x:  { sig: 'int touch_ended_x(int i)',                                 doc: 'Canvas-space X where lifted finger i was last seen, or -1.\nWhere the finger let go — for drops, flick endpoints, releases.' },
  touch_ended_y:  { sig: 'int touch_ended_y(int i)',                                 doc: 'Canvas-space Y where lifted finger i was last seen, or -1.' },
  tapr:           { sig: 'bool tapr(int x, int y, int w, int h)',                    doc: 'True only on the frame a touch ENDED inside this rectangle (edge-triggered, like btnr). The release twin of tapp.\nUse for release-to-fire buttons (slingshots, drag-and-drop targets).\nif (tapr(bx, by, 32, 16)) fire();' },
  touch_controls: { sig: 'void touch_controls(bool on)',                               doc: 'Show or hide the on-screen stick + A/B. Call from your cart to override the editor default.' },
  touch_layout: { sig: 'void touch_layout(int move_mode, int n_buttons)',               doc: 'Opt in to the on-screen controls AND pick the move style + button count (0-4: A/B/X/Y, diamond-laid). move_mode:\nTOUCH_ANALOG (floating — base spawns where the thumb lands, great for frantic free movement),\nTOUCH_ANALOG_FIX (fixed — base stays at a home spot, steadier for precise play),\nTOUCH_DPAD4 (4-way d-pad — grid/precise games) or TOUCH_DPAD8 (8-way d-pad — diagonals too).\nThe stick/d-pad + buttons feed btn(0, ...) just like touch_controls.\n  touch_layout(TOUCH_DPAD4, 4);  // 4-way d-pad + A/B/X/Y' },
  TOUCH_ANALOG: { sig: '#define TOUCH_ANALOG 0',         doc: 'Floating stick: the base spawns wherever the thumb lands (free 8-way movement). Pass to touch_layout().' },
  TOUCH_ANALOG_FIX: { sig: '#define TOUCH_ANALOG_FIX 1', doc: 'Fixed stick: the base stays put at a home spot (steadier, precise). Pass to touch_layout().' },
  TOUCH_DPAD4: { sig: '#define TOUCH_DPAD4 2',           doc: '4-way d-pad: up/down/left/right only, no diagonals. Best for grid & precise games (sokoban, puzzle, rogue). Pass to touch_layout().' },
  TOUCH_DPAD8: { sig: '#define TOUCH_DPAD8 3',           doc: '8-way d-pad: diagonals allowed (both axes can be held at once). Best for fighters / 8-way action. Pass to touch_layout().' },
  touch_ceiling:  { sig: 'int touch_ceiling(void)',                                    doc: 'Max simultaneous fingers this device tracks: 5 on iPhone, 10 on iPad, the digitizer count on Android, 0 on desktop/unknown. One finger MORE than this cancels ALL touches on iOS — design chords and holds to fit the budget.\nif (touch_ceiling() > 0 && touch_ceiling() <= 5) compact_layout = true;' },
  touch_layout_mode: { sig: 'int touch_layout_mode(void)',                            doc: 'Which placement the engine picked this frame for the on-screen controls — one of TOUCH_LAYOUT_OVERLAY / TOUCH_LAYOUT_DECK / TOUCH_LAYOUT_RAILS. Read-only; the engine decides this from the window/game aspect, the cart never sets it.' },
  TOUCH_LAYOUT_OVERLAY: { sig: '#define TOUCH_LAYOUT_OVERLAY 0', doc: 'Controls hug a corner of the game rect, on top — the no-spare-letterbox fallback. What touch_layout_mode() returns.' },
  TOUCH_LAYOUT_DECK:    { sig: '#define TOUCH_LAYOUT_DECK 1',    doc: 'Controls live in a band below the game (portrait). What touch_layout_mode() returns.' },
  TOUCH_LAYOUT_RAILS:   { sig: '#define TOUCH_LAYOUT_RAILS 2',   doc: 'Controls live in bands beside the game (landscape). What touch_layout_mode() returns.' },
  touch_ctrl_scale: { sig: 'float touch_ctrl_scale(void)',                            doc: '0..1 — how much the on-screen controls are currently shrunk to fit a tight deck/rail band (1 = full size). Read-only; mostly useful for debugging placement/sizing.' },
  touch_debug:      { sig: 'void touch_debug(bool on)',                               doc: 'Draw the control band and the current move mode\'s grab-zone outline, plus the placement mode + touch_ctrl_scale() as text — a dev aid for eyeballing placement/sizing work. Leave off in shipped carts.\ntouch_debug(true);' },
  stick_x:        { sig: 'float stick_x()',                                            doc: 'Analog stick X axis: -1.0 to 1.0. Returns 0.0 when no finger is on the stick.' },
  stick_y:        { sig: 'float stick_y()',                                            doc: 'Analog stick Y axis: -1.0 to 1.0. Negative is up.' },
  mouse_x:        { sig: 'int mouse_x()',                                               doc: 'X position of the mouse pointer in canvas coordinates. Always known on desktop, even with no button down (unlike touch).' },
  mouse_y:        { sig: 'int mouse_y()',                                               doc: 'Y position of the mouse pointer in canvas coordinates. Always known on desktop, even with no button down (unlike touch).' },
  mouse_down:     { sig: 'bool mouse_down(int button)',                                 doc: 'True while a mouse button is held. Pass MOUSE_LEFT, MOUSE_RIGHT, or MOUSE_MIDDLE.' },
  mouse_pressed:  { sig: 'bool mouse_pressed(int button)',                              doc: 'True only on the frame the mouse button is pressed. Use for clicks.\nPass MOUSE_LEFT, MOUSE_RIGHT, or MOUSE_MIDDLE.' },
  mouse_released: { sig: 'bool mouse_released(int button)',                             doc: 'True only on the frame the mouse button is released. Pass MOUSE_LEFT, MOUSE_RIGHT, or MOUSE_MIDDLE.' },
  mouse_wheel:    { sig: 'float mouse_wheel()',                                         doc: 'Scroll wheel movement this frame: positive up, negative down, 0 if no scroll.' },
  mouse_world_x:  { sig: 'int mouse_world_x()',                                         doc: 'Mouse X in world space — undoes the active camera() shift. Use to click on a scrolled world instead of writing mouse_x() + cam_x yourself.\nReads the CURRENT camera, so if you read it in update() call camera() in update() too (not just draw()).\nint wx = mouse_world_x();' },
  mouse_world_y:  { sig: 'int mouse_world_y()',                                         doc: 'Mouse Y in world space — undoes the active camera() shift. Reads the current camera (see mouse_world_x).\nint wy = mouse_world_y();' },
  MOUSE_LEFT:     { sig: '#define MOUSE_LEFT 0',                                        doc: 'Left mouse button — pass to mouse_down / mouse_pressed / mouse_released.' },
  MOUSE_RIGHT:    { sig: '#define MOUSE_RIGHT 1',                                       doc: 'Right mouse button — pass to mouse_down / mouse_pressed / mouse_released.' },
  MOUSE_MIDDLE:   { sig: '#define MOUSE_MIDDLE 2',                                      doc: 'Middle mouse button — pass to mouse_down / mouse_pressed / mouse_released.' },
  mouse_cursor:   { sig: 'void mouse_cursor(int kind)',                                 doc: 'Set the pointer shape (CURSOR_DEFAULT / CURSOR_HAND / CURSOR_CROSSHAIR / CURSOR_MOVE / CURSOR_RESIZE_H / CURSOR_TEXT / CURSOR_NO). Persists until you change it, so set it when the context changes, not every frame. Works on web too.\nmouse_cursor(over_button ? CURSOR_HAND : CURSOR_DEFAULT);' },
  CURSOR_DEFAULT: { sig: '#define CURSOR_DEFAULT 0',                                    doc: 'Normal arrow pointer — pass to mouse_cursor().' },
  CURSOR_HAND:    { sig: '#define CURSOR_HAND 1',                                       doc: 'Pointing-hand pointer, for clickable / pressable things — pass to mouse_cursor().' },
  CURSOR_CROSSHAIR:{ sig: '#define CURSOR_CROSSHAIR 2',                                 doc: 'Crosshair pointer, for precise placement / drawing — pass to mouse_cursor().' },
  CURSOR_MOVE:    { sig: '#define CURSOR_MOVE 3',                                       doc: 'Four-way move/resize pointer, for dragging or panning — pass to mouse_cursor().' },
  CURSOR_TEXT:    { sig: '#define CURSOR_TEXT 4',                                       doc: 'I-beam pointer, for text-entry fields — pass to mouse_cursor().' },
  CURSOR_NO:      { sig: '#define CURSOR_NO 5',                                         doc: 'Not-allowed pointer, for an illegal action — pass to mouse_cursor().' },
  CURSOR_RESIZE_H:{ sig: '#define CURSOR_RESIZE_H 6',                                    doc: 'Left-right resize pointer, for dragging an edge/endpoint horizontally (timeline note, slider) — pass to mouse_cursor().' },
  mouse_hide:     { sig: 'void mouse_hide()',                                           doc: 'Hide the OS pointer — typically so you can draw your own cursor sprite at (mouse_x, mouse_y) for a pixel-perfect, screenshot-able cursor. Scoped to the cart window.\nmouse_hide();' },
  mouse_show:     { sig: 'void mouse_show()',                                           doc: 'Show the OS pointer again after mouse_hide().\nmouse_show();' },
  key:            { sig: 'bool key(int k)',                                             doc: "True while a key is held. For letters/digits pass the character: key('A'), key('5'). For special keys use KEY_SPACE, KEY_LEFT, etc." },
  keyp:           { sig: 'bool keyp(int k)',                                            doc: "True only on the frame the key was pressed (edge-triggered). key('A') or KEY_ENTER." },
  keyr:           { sig: 'bool keyr(int k)',                                            doc: "True only on the frame the key was released (the falling edge). Pair with keyp() for hold gestures — note_on() on keyp, note_off() on keyr for hold-to-sustain." },
  text_input:     { sig: 'const char *text_input()',                                   doc: 'The characters typed this frame, as a string (empty if none). For name entry, chat, word games.\nstrcat your buffer with it; handle KEY_BACKSPACE yourself.' },
  paste:          { sig: 'const char *paste()',                                         doc: 'The clipboard text on the frame Ctrl+V (or Cmd+V on Mac) is pressed, else "". The paste companion to text_input() — append it to the same buffer for a text field that also accepts paste.\nExample: for (const char *p = paste(); *p; p++) if (isdigit(*p)) strncat(id, p, 1);' },
  KEY_SPACE:      { sig: '#define KEY_SPACE 32',     doc: 'Spacebar — pass to key() / keyp().' },
  KEY_ENTER:      { sig: '#define KEY_ENTER 257',    doc: 'Enter / Return — pass to key() / keyp().' },
  KEY_BACKSPACE:  { sig: '#define KEY_BACKSPACE 259',doc: 'Backspace — pass to key() / keyp(). Use to delete a character during text entry.' },
  KEY_ESCAPE:     { sig: '#define KEY_ESCAPE 256',   doc: 'Escape — pass to key() / keyp().' },
  KEY_TAB:        { sig: '#define KEY_TAB 258',      doc: 'Tab — pass to key() / keyp().' },
  KEY_LEFT:       { sig: '#define KEY_LEFT 263',     doc: 'Left arrow — pass to key() / keyp().' },
  KEY_RIGHT:      { sig: '#define KEY_RIGHT 262',    doc: 'Right arrow — pass to key() / keyp().' },
  KEY_UP:         { sig: '#define KEY_UP 265',       doc: 'Up arrow — pass to key() / keyp().' },
  KEY_DOWN:       { sig: '#define KEY_DOWN 264',     doc: 'Down arrow — pass to key() / keyp().' },
  print_scaled:   { sig: 'int print_scaled(const char *text, int x, int y, int color, int scale)', doc: 'Draw text bigger for titles and menus using the active font. scale 2 = double size, 3 = triple. Returns x after the last char.\nprint_scaled("GAME OVER", 60, 80, CLR_RED, 2);' },
  print_rot:      { sig: 'int print_rot(const char *text, int x, int y, float deg, int color, int pivot)', doc: 'Draw text rotated `deg` degrees. pivot 0 = rotate around (x,y) = top-left; pivot 1 = rotate around the text center (then (x,y) is that center). Returns x after the last char.\nprint_rot("TILT!", 100, 60, 15, CLR_YELLOW, 1);' },
  print_rot_scaled:{ sig: 'int print_rot_scaled(const char *text, int x, int y, float deg, int scale, int color, int pivot)', doc: 'Rotated AND scaled in one call — scale 2 = double size, 3 = triple. Same pivot rule as print_rot (0 = top-left, 1 = center). Stays crisp at integer scale (point filter). For big tilted titles, ransom-note text, etc.\nprint_rot_scaled("BIG", 80, 60, -8, 3, CLR_RED, 1);' },
  text_width:     { sig: 'int text_width(const char *text)',                            doc: 'Pixel width of text using the active font (set with font()). Use it to center text inside your own box:\nprint(s, bx + (bw - text_width(s))/2, y, c);' },
  font:           { sig: 'void font(int f)',                                            doc: 'Set the active font for all print calls. font(FONT_NORMAL) resets to the default 8×8.\nfont(FONT_SMALL); print("tiny hud", 4, 4, CLR_WHITE); font(FONT_NORMAL);' },
  FONT_NORMAL:    { sig: '#define FONT_NORMAL 0',                                       doc: 'Default 8×8 DOS font — pass to font() to reset.\nfont(FONT_NORMAL);' },
  FONT_SMALL:     { sig: '#define FONT_SMALL 1',                                        doc: 'Compact 4×6 font — fits ~64 chars across 320px. Good for HUD lines and stat tables.\nfont(FONT_SMALL);' },
  FONT_TINY:      { sig: '#define FONT_TINY 2',                                         doc: 'Tiny 3×5 font — fits ~80 chars across 320px. Maximum info density.\nfont(FONT_TINY);' },
  FONT_COMIC:     { sig: '#define FONT_COMIC 3',                                        doc: 'Comic Mono Bold baked to crisp pixels (18px, 10×20 cells) — a friendly rounded handwriting look. Great for titles, dialogue, and anything that wants warmth over a terminal feel.\nfont(FONT_COMIC); print("hello!", 80, 40, CLR_WHITE);' },
  FONT_THIN:      { sig: '#define FONT_THIN 4',                                         doc: 'IBM CGA "thin" 8×8 — the narrow-stroke alternate from the CGA ROM. Same footprint as the default 8×8 but lighter and more delicate; nice for dense UI or a softer retro-DOS feel.\nfont(FONT_THIN); print("loading...", 8, 8, CLR_GREEN);' },
  print_outline:  { sig: 'int print_outline(const char *text, int x, int y, int color, int outline_color)', doc: 'Draw text with a 1px outline in all 8 directions. Maximum legibility on any background. Returns x after the last char.\nprint_outline("LEVEL 1", 60, 90, CLR_YELLOW, CLR_BLACK);' },
  oval:           { sig: 'void oval(int x, int y, int rx, int ry, int color)',          doc: 'Ellipse border centered at (x,y). rx/ry are the half-width and half-height.' },
  ovalfill:       { sig: 'void ovalfill(int x, int y, int rx, int ry, int color)',      doc: 'Filled ellipse centered at (x,y). Great for squashed circles, eyes, shadows.' },
  arc:            { sig: 'void arc(int x, int y, int radius, float start_deg, float end_deg, int color)', doc: "Draw part of a circle's rim, from start_deg to end_deg (degrees, 0=right, 90=down — same as dx/dy).\narc(80, 80, 20, 0, 90, 7);" },
  arcfill:        { sig: 'void arcfill(int x, int y, int radius, float start_deg, float end_deg, int color)', doc: 'Filled pie wedge (a sector) from start_deg to end_deg. For cooldown sweeps, pie slices, a half-circle (0..180).\narcfill(80, 80, 20, -90, 0, 8);' },
  arcoutline:     { sig: 'void arcoutline(int x, int y, int radius, float start_deg, float end_deg, int color)', doc: 'Outline of a filled pie wedge — the rim plus the two straight radial edges. Hugs arcfill() exactly (use arc() for just the curved rim).\narcoutline(80, 80, 20, -90, 0, 8);' },
  ring:           { sig: 'void ring(int x, int y, int r_in, int r_out, float start_deg, float end_deg, int color)', doc: 'Filled thick arc — the band between r_in and r_out, from start_deg to end_deg. For gauges, radial bars, dials.\nring(80, 80, 14, 20, 0, 270, 11);' },
  ringoutline:    { sig: 'void ringoutline(int x, int y, int r_in, int r_out, float start_deg, float end_deg, int color)', doc: 'Outline of a ring/annulus sector — both rims and (for a partial sweep) the two radial edges. Hugs ring() exactly.\nringoutline(80, 80, 14, 20, 0, 270, 11);' },
  pal:            { sig: 'void pal(int c0, int c1)',                                    doc: 'Remap a palette color: everything drawn as c0 now draws as c1 — shapes AND sprites. ⚠ STICKY: persists across every later draw AND into the next frame until pal_reset() — forget it and the swap leaks onto everything you draw after.\nDraw "magic" placeholder colors in a sprite, then pal() them per-entity for clothes/team recolors. Also hit-flash, fades.\npal(28, my_shirt); spr(0, x, y); pal_reset();' },
  pal_reset:      { sig: 'void pal_reset()',                                            doc: 'Undo every pal() swap — back to the normal 32 colors.' },
  fade:           { sig: 'void fade(float amount)',                                     doc: 'Darken the whole screen toward black for ONE frame. 0 = normal, 1 = fully black. For fade-in/out transitions between rooms or scenes.\nImmediate-mode: it clears automatically next frame, so call it every frame you want the screen dimmed (e.g. inside a game-over overlay). No need to reset it by hand.\nif (gameover) fade(0.5f);' },
  shake:          { sig: 'void shake(float amount)',                                    doc: 'Kick the screen by `amount` pixels. Call it on impacts, explosions, landings — instant game feel.\n✓ ENGINE-CLEARED: decays on its own over a few frames (like clip, you never reset it) — so you just call it once on the hit.' },
  dt:             { sig: 'float dt()',                                                  doc: 'Seconds since the last frame (already clamped for hitches). Multiply movement and decay by it so speed is the same on any framerate:\nx += 60 * dt();  // 60 px per second' },
  save_bytes:     { sig: 'void save_bytes(const void *data, int len)',                  doc: 'Save a whole block of bytes (a struct or array) that survives between runs — for state too big for the 64 int slots.\nsave_bytes(&world, sizeof world);' },
  load_bytes:     { sig: 'int load_bytes(void *out, int max)',                          doc: 'Read bytes saved with save_bytes() into `out` (up to max). Returns how many bytes were read (0 if never saved).\nload_bytes(&world, sizeof world);' },
  cls:        { sig: 'void cls(int color)',                                            doc: 'Clear the screen to a palette color index (0–31).' },
  colorkey:   { sig: 'void colorkey(int color)',                                       doc: 'Choose which palette color is treated as transparent when drawing sprites.\nAny pixel matching this color is skipped — so the background shows through.\nPass -1 to turn transparency off. Call once when the color changes, not every frame.' },
  spr:        { sig: 'void spr(int index, int x, int y)',                             doc: 'Draw a sprite by its index at position (x, y).' },
  sprf:       { sig: 'void sprf(int index, int x, int y, bool flip_x, bool flip_y)',  doc: 'Like spr() but can be flipped horizontally and/or vertically.\nUseful for left/right facing characters.' },
  fillp:        { sig: 'void fillp(int pattern, int hole_color)',  doc: "PICO-8-style global fill pattern. Once set, the normal fills — rectfill, circfill, ovalfill, trifill — draw the 4×4 pattern: the draw color fills the 0-bits, the 1-bits use hole_color (pass -1 to make them transparent so the background shows through). ⚠ STICKY (you own this): stays on for every later fill AND into the next frame until fillp_reset() — forget it and unrelated shapes come out dithered.\nfillp(FILL_CHECKER, CLR_DARK_BLUE); rectfill(0,0,320,200, CLR_BLUE); fillp_reset();" },
  fillp_reset:  { sig: 'void fillp_reset()', doc: 'Turn off the global fill pattern set by fillp() — fills go back to solid.' },
  blend:        { sig: 'void blend(int mode)',  doc: "Start MIXING every following draw with what's already on screen (glow, glass, fog) instead of overwriting. mode: BLEND_ADD (additive glow — fire, magic, lasers; brightens the background), BLEND_AVG (50% — glass, water, soft shadow), BLEND_MUL (multiply — fog, darken + tint), BLEND_SUB (carve light out toward black — cold shadow, scorch), BLEND_NONE (off). The result snaps to the nearest palette color, so a little banding IS the look. ⚠ STICKY: stays on until blend_reset().\nblend(BLEND_ADD); circfill(x,y,8, CLR_ORANGE); blend_reset();" },
  blend_reset:  { sig: 'void blend_reset()', doc: 'Stop blending — following draws overwrite normally again (mode BLEND_NONE).' },
  BLEND_NONE:   { sig: '#define BLEND_NONE 0', doc: 'blend() mode: plain overwrite (the default — no mixing).' },
  BLEND_AVG:    { sig: '#define BLEND_AVG 1',  doc: 'blend() mode: 50% average with the background — glass, water, soft shadow (AVG over black = a drop shadow).' },
  BLEND_ADD:    { sig: '#define BLEND_ADD 2',  doc: 'blend() mode: additive — brightens whatever is behind. Glow, light, fire, lasers; overlapping draws stack toward white.' },
  BLEND_MUL:    { sig: '#define BLEND_MUL 3',  doc: 'blend() mode: multiply — deepens and tints the background. Fog, darken, colored shadow; draws vanish over black.' },
  BLEND_SUB:    { sig: '#define BLEND_SUB 4',  doc: 'blend() mode: subtractive — carves light out of the background toward black. Cold shadow, scorch; the opposite of BLEND_ADD.' },
  fillp_anchor: { sig: 'void fillp_anchor(int ox, int oy)', doc: "Move the fill-pattern lattice origin to (ox,oy). By default the 4×4 pattern is pinned to world (0,0), so a MOVING shape slides over a fixed grid and the dither appears to crawl. Anchor to a shape's own center right before filling it and the pattern travels with the shape. fillp_anchor(0,0) restores the default.\nfillp(FILL_CHECKER, CLR_DARK_BLUE); fillp_anchor(x, y); circfill(x, y, 8, CLR_BLUE); fillp_anchor(0,0);" },
  FILL_SOLID:   { sig: '#define FILL_SOLID 0xFFFF',   doc: 'Pattern: fully solid (all bits set). Pass to fillp().' },
  FILL_CHECKER: { sig: '#define FILL_CHECKER 0xA5A5', doc: 'Pattern: 50% checkerboard.' },
  FILL_DOTS:    { sig: '#define FILL_DOTS 0x8020',    doc: 'Pattern: sparse dots.' },
  FILL_HLINES:  { sig: '#define FILL_HLINES 0xF0F0',  doc: 'Pattern: horizontal stripes.' },
  FILL_VLINES:  { sig: '#define FILL_VLINES 0xAAAA',  doc: 'Pattern: vertical stripes.' },
  FILL_DIAG:    { sig: '#define FILL_DIAG 0x8421',    doc: 'Pattern: diagonal lines.' },
  FILL_GRID:    { sig: '#define FILL_GRID 0xF888',    doc: 'Pattern: grid / brick lines.' },
  spr_rot:    { sig: 'void spr_rot(int index, int x, int y, float deg)',              doc: 'Draw a sprite spun `deg` degrees around its own center. (x,y) is the top-left, same as spr().\nThe everyday rotate — a turning ship, a spinning pickup. For vanilla sprites just use spr().' },
  sspr_ex:    { sig: 'void sspr_ex(int sx, int sy, int sw, int sh, int dx, int dy, int dw, int dh, float deg, int ox, int oy)', doc: 'The works: copy a source sub-rect (sx,sy,sw,sh) of the sheet to a dest rect (dx,dy,dw,dh) — so it scales — rotated `deg` degrees around the pivot (ox,oy), measured inside the dest from its top-left. Flip by passing a negative sw or sh.\nRotate around the dest center with ox=dw/2, oy=dh/2.' },
  sspr:       { sig: 'void sspr(int sx, int sy, int sw, int sh, int dx, int dy, int dw, int dh)', doc: 'Stretched sprite. Copies a sub-rectangle of the sprite sheet (sx,sy,sw,sh) to a destination rectangle (dx,dy,dw,dh).\nNon-equal sizes scale the result.' },
  pget:       { sig: 'int pget(int x, int y)',                                        doc: "Read the palette index at (x, y). Reads from the previous frame's canvas.\nReturns 0 if the pixel does not match any palette color or is outside the screen.\nNote: read-back is OFF by default — call enable_pget(true) in init() first, or pget always returns 0.\nNote: true-colour pixels from pset_rgb/rectfill_rgb usually match no palette index — use pget_rgb to read those back." },
  pget_rgb:   { sig: 'int pget_rgb(int x, int y)',                                    doc: "Read the raw 0xRRGGBB colour at (x, y), bypassing the palette — the true-colour read-back that pairs with pset_rgb.\nReturns -1 if off-screen (so a real black pixel, 0x000000, isn't ambiguous). Reads the previous frame's canvas, like pget.\nNeeds enable_pget(true) in init() (off by default), like pget.\nLets a cart read its own true-colour canvas and write it back — feedback shaders, trails, cellular automata.\nint c = pget_rgb(x, y);" },
  enable_pget:{ sig: 'void enable_pget(bool on)',                                     doc: "Turn the canvas read-back ON so pget / pget_rgb / touching_color can read last frame's pixels. OFF by default — the read-back costs a GPU stall + memory each frame, so only carts that read pixels pay for it.\nCall enable_pget(true) once in init() if your cart always reads, or toggle it around a reading mode (e.g. a paint tool) to pay only while active.\nForget it and pget returns 0 (you'll see a one-time warning in the log).\nenable_pget(true);" },
  sget:       { sig: 'int sget(int sx, int sy)',                                      doc: "Read the palette index of a spritesheet pixel at (sx, sy) — straight from the sheet, not the canvas, so it's a stable data lookup. Lets you treat sprites as data: paint a level (1 pixel = 1 block, color = block type) and read it back, or build lookup tables.\nReturns 0 if (sx, sy) is outside the sheet.\nint block = sget(x, y);" },
  camera:     { sig: 'void camera(int x, int y)',                                     doc: 'Plain camera: shifts all subsequent drawing by (-x, -y), with no zoom or rotation. Lets you scroll the world without per-call math.\n⚠ STICKY (you own this): the shift persists across frames until you change it — camera(0, 0) resets it, use that to switch back to screen space for a HUD.' },
  camera_ex:  { sig: 'void camera_ex(int x, int y, float zoom, float angle)',         doc: 'Camera with zoom and rotation, pivoting on the screen center. zoom 1.0 = normal, 2.0 = 2x in, 0.5 = out; angle in degrees.\nFeed your scroll x/y each frame; for a screen-space HUD after zooming, call camera(0, 0).\n⚠ STICKY (you own this): persists across frames until you change it. If you read mouse_world_*() in update(), set the camera in update() too — not just draw().\n⚠ ROTATION (angle != 0): SOFTWARE fills (trifill/polyfill/circfill/ngonfill/thickline…) staircase into a dotted lattice of holes when the view spins — they rasterise in world space. Use GPU primitives (rectfill, rectfill_rot, line, tritex) for rotated-in-world shapes. See api-notes.md "software fills break up under a ROTATED camera".\ncamera_ex(camx, camy, 2.0f, 0);' },
  smooth_zoom: { sig: 'void smooth_zoom(bool on)',                                    doc: 'Fixes thin-line CRAWL under a fractional camera_ex() zoom. Renders the zoomed world at 1:1 into an offscreen, then scales it to the screen in one smooth blit — so curbs/dashes/grids stop re-rasterizing (shimmering) every frame the zoom changes.\nOne toggle, default OFF. Affects only the world drawn between camera_ex() and camera(0,0) — the HUD stays crisp. macOS native only (no-op on web).\nTurn it on once (e.g. in init), not per frame.\nsmooth_zoom(true);' },
  follow:     { sig: 'void follow(int tx, int ty, int world_w, int world_h)', doc: 'Center the camera on (tx, ty), clamped so world edges never show.\nworld_w and world_h are the total world size in pixels.\nTypically called at the end of update() with the player position.' },
  clip:       { sig: 'void clip(int x, int y, int w, int h)',                         doc: 'Restrict drawing to a rectangle. Useful for UI panels, split-screen, transitions.\nAlways in SCREEN space — it does not follow camera_ex() zoom/rotation.\nclip(0, 0, 0, 0) disables clipping.\n✓ ENGINE-CLEARED: unlike camera/pal/fillp/fade (which you must reset), the engine turns clip off for you at the end of every frame — so a forgotten clip can never blank the next frame.' },
  zoom_rect:  { sig: 'void zoom_rect(int sx, int sy, int sw, int sh, int dx, int dy, int dw, int dh)', doc: 'Copy the canvas region (sx,sy,sw,sh) into the rect (dx,dy,dw,dh), scaled.\nNearest-neighbor, so a zoom shows crisp doubled pixels — magnifier loupe,\npicture-in-picture, minimap, rear-view mirror.\nIt samples the frame drawn SO FAR, so call it AFTER the content you want to copy.\nzoom_rect(px - 20, py - 12, 40, 24, 0, 0, 160, 96);  // 4x loupe of a 40x24 patch' },
  mget:       { sig: 'int mget(int cx, int cy)',                                       doc: 'Read the tile index stored in map cell (cx, cy). Returns 0 if out of bounds.\nFor pixel-space collision use tile_at(px, py), which handles the cell size for you.' },
  mset:       { sig: 'void mset(int cx, int cy, int sprite_index)',                    doc: 'Write a sprite index into map cell (cx, cy). Out-of-bounds writes are silently ignored.' },
  map:        { sig: 'void map(int cx, int cy, int sx, int sy, int cw, int ch)',       doc: 'Draw a cw×ch chunk of the map starting at cell (cx,cy) to screen position (sx,sy).\nEach cell is a CELL_W×CELL_H rect of the spritesheet (set in the map tab). Value-0 cells are skipped.\nRespects camera() and map_scale().' },
  map_scale:  { sig: 'void map_scale(int n)',                                          doc: 'Integer zoom for map drawing. map_scale(1) draws cells at their native CELL_W×CELL_H (default);\nmap_scale(4) draws them 4× as big. tile_at() and touching_map() follow the same scale.' },
  MAP_W:      { sig: '#define MAP_W 128',                                              doc: 'Map width in cells.' },
  MAP_H:      { sig: '#define MAP_H 64',                                               doc: 'Map height in cells.' },
  print:          { sig: 'int print(const char *text, int x, int y, int color)',          doc: 'Draw text at (x, y) using the active font. Returns x after the last char — use it to chain segments or detect overflow.\nint x2 = print("score ", 4, 4, CLR_WHITE); print(str("%d", score), x2, 4, CLR_YELLOW);' },
  print_centered: { sig: 'int print_centered(const char *text, int x, int y, int color)', doc: 'Draw text centered on x. Pass SCREEN_W/2 to center on screen.\nprint_centered("score", SCREEN_W/2, 10, CLR_WHITE);' },
  print_right:    { sig: 'int print_right(const char *text, int right_x, int y, int color)', doc: 'Draw text right-aligned so its last character ends at right_x. Returns x after the last char.' },
  hint:           { sig: 'void hint(const char *text)', doc: 'Draw a one-line control-hint footer along the bottom of the screen in muted grey.\nAuto-picks the largest of the 8x8/small/tiny fonts that fits the screen width, so the line never runs off the edge.\nThe canonical "what do the keys do" line.\nExample: hint("Z jump   X shoot   arrows move");' },
  rect:       { sig: 'void rect(int x, int y, int w, int h, int color)',              doc: 'Draw a rectangle border.' },
  rectfill:   { sig: 'void rectfill(int x, int y, int w, int h, int color)',          doc: 'Draw a filled rectangle.' },
  rectfill_rgb: { sig: 'void rectfill_rgb(int x, int y, int w, int h, int hex)',       doc: 'Filled rectangle in a raw 0xRRGGBB colour, bypassing the 32-colour palette — true 24-bit colour. One call per cell for chunky CPU shaders / true-colour gradients.\nrectfill_rgb(x, y, 4, 4, 0x33ccff);' },
  rectfill_rot: { sig: 'void rectfill_rot(int cx, int cy, int w, int h, float deg, int color)', doc: 'Filled rectangle CENTRED at (cx, cy) and rotated `deg` degrees. Drawn as real GPU geometry, so it stays solid (HOLE-FREE) under a rotated camera_ex() — unlike trifill/polyfill, which fill in software and break into a dotted lattice when the view spins. Use it for oriented single-colour shapes: cars, debris, blades.\nrectfill_rot(x, y, 28, 14, ang, CLR_RED);' },
  bar:        { sig: 'void bar(int x, int y, int w, int h, float pct, int fill, int bg)', doc: 'Draw a progress/health bar: a bg-colored box with a left-to-right fill.\npct is 0..1 (clamped). bar(10, 8, 80, 5, hp / 100.0f, CLR_RED, CLR_DARK_RED);' },
  circ:       { sig: 'void circ(int x, int y, int radius, int color)',                doc: 'Draw a circle border.' },
  circfill:   { sig: 'void circfill(int x, int y, int radius, int color)',            doc: 'Draw a filled circle.' },
  tri:        { sig: 'void tri(int x1, int y1, int x2, int y2, int x3, int y3, int color)',     doc: 'Draw a triangle border through three points.' },
  trifill:    { sig: 'void trifill(int x1, int y1, int x2, int y2, int x3, int y3, int color)', doc: 'Draw a filled triangle. Vertex order does not matter.' },
  tritex:     { sig: 'void tritex(int x1, int y1, float u1, float v1, int x2, int y2, float u2, float v2, int x3, int y3, float u3, float v3)',
               doc: 'Texture-mapped triangle — the textured-3D primitive. Each corner maps a screen point (x,y) to a pixel on the sprite sheet (u,v, in sheet pixels, 0–127). The texture is interpolated across the triangle in screen space with no perspective correction — the authentic affine "swimmy" PS1 look. For 3D, project your model to 2D yourself, then feed the screen coords here. Sampling is nearest-neighbour; sheet transparency shows through.\ntritex(10,10,0,0, 90,20,16,0, 50,90,8,16);' },
  line:       { sig: 'void line(int x1, int y1, int x2, int y2, int color)',          doc: 'Draw a line from (x1, y1) to (x2, y2).' },
  bezier:      { sig: 'void bezier(int x0, int y0, int cx, int cy, int x1, int y1, int color)', doc: 'Quadratic Bezier curve from (x0,y0) to (x1,y1) pulled toward control point (cx,cy). One handle, one smooth bend.\nbezier(10, 100, 160, 10, 310, 100, CLR_WHITE);' },
  pset:       { sig: 'void pset(int x, int y, int color)',                            doc: 'Set a single pixel at (x, y). Pairs with pget().' },
  pset_rgb:   { sig: 'void pset_rgb(int x, int y, int hex)',                           doc: 'Set a single pixel to a raw 0xRRGGBB colour, bypassing the 32-colour palette — full 24-bit colour. For CPU shaders and true-colour gradients.\npset_rgb(x, y, 0xff8800);' },
  BTN_UP:     { sig: '#define BTN_UP 0',                                              doc: 'Up button.' },
  BTN_DOWN:   { sig: '#define BTN_DOWN 1',                                            doc: 'Down button.' },
  BTN_LEFT:   { sig: '#define BTN_LEFT 2',                                            doc: 'Left button.' },
  BTN_RIGHT:  { sig: '#define BTN_RIGHT 3',                                           doc: 'Right button.' },
  BTN_A:      { sig: '#define BTN_A 4',                                               doc: 'A button. Player 0: Z  Player 1: J. Remappable in settings → controls.' },
  BTN_B:      { sig: '#define BTN_B 5',                                               doc: 'B button. Player 0: X  Player 1: K. Remappable in settings → controls.' },
  BTN_X:      { sig: '#define BTN_X 6',                                               doc: '3rd face button (Xbox/PlayStation/Switch-style A/B/X/Y vocabulary). Player 0: C  Player 1: L. Remappable in settings → controls.' },
  BTN_Y:      { sig: '#define BTN_Y 7',                                               doc: '4th face button. Player 0: V  Player 1: ;. Remappable in settings → controls.' },
  SCREEN_W:   { sig: '#define SCREEN_W 320',                                          doc: 'Width of the screen in pixels. Configurable in settings. This is the MAX size; a resizable cart reads the live size with screen_w().' },
  SCREEN_H:   { sig: '#define SCREEN_H 200',                                          doc: 'Height of the screen in pixels. Configurable in settings. This is the MAX size; a resizable cart reads the live size with screen_h().' },
  screen_w:   { sig: 'int screen_w()',                                               doc: 'Active canvas width in pixels. Equals SCREEN_W on a normal cart; on a cart built with -DDE_RESIZABLE it reflows live as the window resizes. Lay out your UI against it (see lay.h) so it adapts.\nBox root = box(0, 0, screen_w(), screen_h());' },
  screen_h:   { sig: 'int screen_h()',                                               doc: 'Active canvas height in pixels. Equals SCREEN_H on a normal cart; on a cart built with -DDE_RESIZABLE it reflows live as the window resizes.\nBox root = box(0, 0, screen_w(), screen_h());' },
  safe_rect:  { sig: 'void safe_rect(int *x, int *y, int *w, int *h)',               doc: 'Usable rectangle after the device safe-area insets (notch, home bar, status bar). On desktop it is the whole canvas (0,0,screen_w,screen_h); on iOS it excludes the chrome. Bleed your background to screen_w/h, but lay CONTROLS inside this rect so nothing hides under the notch.\nint x,y,w,h; safe_rect(&x,&y,&w,&h); Box ui = box(x,y,w,h);' },
  finger_px:  { sig: 'int finger_px()',                                              doc: 'Logical px for a comfortable ~44pt touch target, from the device backing scale (22 at the iOS 2x pixel chunk). Size finger controls to this instead of a raw px guess — a hardcoded number only works by the SCALE=1 coincidence and breaks on a different chunk / HiDPI.\nfloat fu = finger_px(); ui_button(x, y, fu, fu, "go");' },
  device_class: { sig: 'int device_class()',                                         doc: 'Classify the live screen: 0 = TALL (phone portrait), 1 = WIDE (phone landscape), 2 = ROOMY (tablet). Pick your arrangement off this, not a device name — the same 0/1/2 as disclose.h\'s DiscShape.\nif (device_class() == 2) grid_layout(); else stack_layout();' },
  CLR_BLACK:          { sig: '#define CLR_BLACK 0',           doc: 'Palette index for black (#000000).' },
  CLR_DARK_BLUE:      { sig: '#define CLR_DARK_BLUE 1',       doc: 'Palette index for dark blue (#1d2b53).' },
  CLR_DARK_PURPLE:    { sig: '#define CLR_DARK_PURPLE 2',     doc: 'Palette index for dark purple (#7e2553).' },
  CLR_DARK_GREEN:     { sig: '#define CLR_DARK_GREEN 3',      doc: 'Palette index for dark green (#008751).' },
  CLR_BROWN:          { sig: '#define CLR_BROWN 4',           doc: 'Palette index for brown (#ab5236).' },
  CLR_DARK_GREY:      { sig: '#define CLR_DARK_GREY 5',       doc: 'Palette index for dark grey (#5f574f).' },
  CLR_LIGHT_GREY:     { sig: '#define CLR_LIGHT_GREY 6',      doc: 'Palette index for light grey (#c2c3c7).' },
  CLR_WHITE:          { sig: '#define CLR_WHITE 7',           doc: 'Palette index for white (#fff1e8).' },
  CLR_RED:            { sig: '#define CLR_RED 8',             doc: 'Palette index for red (#ff004d).' },
  CLR_ORANGE:         { sig: '#define CLR_ORANGE 9',          doc: 'Palette index for orange (#ffa300).' },
  CLR_YELLOW:         { sig: '#define CLR_YELLOW 10',         doc: 'Palette index for yellow (#ffec27).' },
  CLR_GREEN:          { sig: '#define CLR_GREEN 11',          doc: 'Palette index for green (#00e436).' },
  CLR_BLUE:           { sig: '#define CLR_BLUE 12',           doc: 'Palette index for blue (#29adff).' },
  CLR_INDIGO:         { sig: '#define CLR_INDIGO 13',         doc: 'Palette index for indigo (#83769c).' },
  CLR_PINK:           { sig: '#define CLR_PINK 14',           doc: 'Palette index for pink (#ff77a8).' },
  CLR_LIGHT_PEACH:    { sig: '#define CLR_LIGHT_PEACH 15',    doc: 'Palette index for light peach (#ffccaa).' },
  CLR_BROWNISH_BLACK: { sig: '#define CLR_BROWNISH_BLACK 16', doc: 'Palette index for brownish black (#291814).' },
  CLR_DARKER_BLUE:    { sig: '#define CLR_DARKER_BLUE 17',    doc: 'Palette index for darker blue (#111d35).' },
  CLR_DARKER_PURPLE:  { sig: '#define CLR_DARKER_PURPLE 18',  doc: 'Palette index for darker purple (#422136).' },
  CLR_BLUE_GREEN:     { sig: '#define CLR_BLUE_GREEN 19',     doc: 'Palette index for blue green (#125359).' },
  CLR_DARK_BROWN:     { sig: '#define CLR_DARK_BROWN 20',     doc: 'Palette index for dark brown (#742f29).' },
  CLR_DARKER_GREY:    { sig: '#define CLR_DARKER_GREY 21',    doc: 'Palette index for darker grey (#49333b).' },
  CLR_MEDIUM_GREY:    { sig: '#define CLR_MEDIUM_GREY 22',    doc: 'Palette index for medium grey (#a28879).' },
  CLR_LIGHT_YELLOW:   { sig: '#define CLR_LIGHT_YELLOW 23',   doc: 'Palette index for light yellow (#f3ef7d).' },
  CLR_DARK_RED:       { sig: '#define CLR_DARK_RED 24',       doc: 'Palette index for dark red (#be1250).' },
  CLR_DARK_ORANGE:    { sig: '#define CLR_DARK_ORANGE 25',    doc: 'Palette index for dark orange (#ff6c24).' },
  CLR_LIME_GREEN:     { sig: '#define CLR_LIME_GREEN 26',     doc: 'Palette index for lime green (#a8e72e).' },
  CLR_MEDIUM_GREEN:   { sig: '#define CLR_MEDIUM_GREEN 27',   doc: 'Palette index for medium green (#00b543).' },
  CLR_TRUE_BLUE:      { sig: '#define CLR_TRUE_BLUE 28',      doc: 'Palette index for true blue (#065ab5).' },
  CLR_MAUVE:          { sig: '#define CLR_MAUVE 29',          doc: 'Palette index for mauve (#754665).' },
  CLR_DARK_PEACH:     { sig: '#define CLR_DARK_PEACH 30',     doc: 'Palette index for dark peach (#ff6e59).' },
  CLR_PEACH:          { sig: '#define CLR_PEACH 31',          doc: 'Palette index for peach (#ff9d81).' },
  sfx:          { sig: 'void sfx(int n)',                                             doc: 'Play sound effect slot n. -1 stops all currently-ringing sounds (held note_on() voices survive).\nThe slots are built-in DEMO data (0 coin, 1 zap, 2 jump, 3 explosion) — carts don’t define slots. To make your OWN sound, two carts in the carts panel export paste-ready C code (a step array + a tiny player): “sfx editor” (draw the pitch contour by hand) and “sfx generator” (17 sliders + RANDOM/MUTATE, bfxr-style). Press E in either. For music, sequence notes off the beat clock (every()/euclid() + note()/hit()).\nsfx(0);' },
  note:         { sig: 'void note(int midi, int instr, int vol)',                     doc: 'One-shot note (~250ms).\nmidi: MIDI note (60 = middle C). instr: INSTR_*.  vol: 0–7.' },
  hit:          { sig: 'void hit(int midi, int instr, int vol, int dur_ms)',          doc: 'Like note() but you choose how long it rings.\nClosed hihat: hit(72, INSTR_NOISE, 3, 30).\nOpen hihat: hit(72, INSTR_NOISE, 3, 200).\nStaccato vs sustained = same lever.' },
  note_on:      { sig: 'int note_on(int midi, int instr, int vol)',                   doc: 'Start a SUSTAINED note and get a handle back — it rings until you note_off() it (unlike note(), which auto-ends). vol 0 starts it silent.\nKeep the handle to drive it live or release it.\nint h = note_on(60, INSTR_SAW, 5);' },
  note_off:     { sig: 'void note_off(int handle)',                                   doc: 'Release a held note — its envelope fades out (the release stage).\nnote_off(h);' },
  note_pitch:   { sig: 'void note_pitch(int handle, float midi)',                     doc: 'Slide a held note to a new pitch. float lets you go between notes (theremin, glide). Smoothed automatically — no click.\nnote_pitch(h, 36 + speed * 0.6);' },
  note_vol:     { sig: 'void note_vol(int handle, float vol)',                        doc: 'Change a held note’s volume live, 0–7 — fractions now allowed (e.g. 3.7) for smooth fades and continuous dynamics (bowing, breath, occlusion). 0 = silent but still alive (can swell back up); use note_off() to actually end it. Whole-number calls behave exactly as before.\nnote_vol(h, level * 7.0f);  // level 0..1 → smooth' },
  note_cutoff:  { sig: 'void note_cutoff(int handle, int hz)',                        doc: 'Sweep a held note’s filter cutoff live — the classic filter-sweep wah. Needs a filter on its instrument slot (instrument_filter). An LFO on the slot still shimmers on top.\nnote_cutoff(h, 400 + lever * 3000);' },
  note_res:     { sig: 'void note_res(int handle, float resonance)',                  doc: 'Sweep a held note’s filter resonance live, 0–15 — fractions now allowed for a smooth (no-zipper) resonance sweep. 0 = soft, 15 = whistly peak. Pair with note_cutoff() and you get the acid squelch — both moving together.\nnote_res(h, 12.0f);' },
  note_lfo:     { sig: 'void note_lfo(int handle, int which, int dest, float rate_hz, float depth)', doc: 'Retune a held note’s LFO `which` (0–2) live — same shape as instrument_lfo() but on a ringing voice. dest: LFO_PITCH/DUTY/VOLUME/CUTOFF; depth 0 = off. Phase is kept, so it never clicks. Drag a vibrato wider while a chord rings.\nnote_lfo(h, 0, LFO_PITCH, 6.0, 0.4);' },
  note_env:     { sig: 'void note_env(int handle, int which, int dest, int attack_ms, int decay_ms, float amount)', doc: 'Set a held note’s mod-envelope `which` (0–2) live — same shape as instrument_env() but on a ringing voice. dest: ENV_CUTOFF/ENV_PITCH/ENV_DUTY; amount 0 = off. Lets a patch (e.g. modrack) wire an envelope to filter or pitch per voice.\nnote_env(h, 0, ENV_CUTOFF, 0, 120, 1500);' },
  note_harmonics: { sig: 'void note_harmonics(int handle, float x)',                  doc: 'Live engine macro on a held note, slewed (no zipper) — the held-voice twin of instrument_harmonics(). For PLUCK this is the one macro that reshapes a string WHILE it rings (it is the feedback): drag it up and a dying pluck blooms into a drone.\nnote_harmonics(h, 1.0f);  // let it ring' },
  note_timbre:  { sig: 'void note_timbre(int handle, float x)',                       doc: 'Live engine macro on a held note, slewed — twin of instrument_timbre(). For PLUCK the pick is already struck, so this lands on the NEXT note; future engines (organ brightness…) will answer it mid-note.\nnote_timbre(h, 0.8f);' },
  note_morph:   { sig: 'void note_morph(int handle, float x)',                        doc: 'Live engine macro on a held note, slewed — twin of instrument_morph(). For PLUCK the pick is already struck, so this lands on the NEXT note; future engines will answer it mid-note.\nnote_morph(h, 0.3f);' },
  voice_nasal:  { sig: 'void voice_nasal(int handle, float amount)',                   doc: 'INSTR_VOICE nasal color on a held note: 0 = open vowel .. 1 = hummed/nasal — the honk, the Tibetan-monk chant. The voice\'s 4th axis, alongside the harmonics/timbre/morph macros (VOWEL / SIZE / EFFORT). For the chant drone: low pitch + nasal high + soft effort.\nvoice_nasal(h, 0.8f);' },
  voice_consonant: { sig: 'void voice_consonant(int handle, int id)',                  doc: 'Begin a held INSTR_VOICE note with a consonant onset that morphs into the vowel — "bah", "mah", "sss-ah". Call right after note_on. id 0..21 (b d g m n l s sh ng r w y dh f v z zh th p t k ch), -1 = none. A timed onset; pair with voice_coda for VC/CVC, or re-fire mid-note for connected speech.\nint h = note_on(50, 5, 6);  voice_consonant(h, 3);  // "mah"' },
  voice_coda:   { sig: 'void voice_coda(int handle, int id)',                          doc: 'Close a held INSTR_VOICE note ON a consonant: the vowel morphs into it — "ahh-m", "oo-d". Call right before note_off. id 0..21, -1 = none. The mirror of voice_consonant; voiced ids (b d g m n l ng r w y) stay sung.\nvoice_coda(h, 3);  note_off(h);  // "...m"' },
  instrument_mode: { sig: 'void instrument_mode(int slot, int idx, float value)',       doc: 'ADVANCED — the per-engine aux channel, NOTE-ON face: a slot\'s structure/mode params past the 3 macros (read at the next note_on, so it picks the engine\'s mode rather than sweeping live). idx is per-engine — use the MODE_* names. GUITAR/PIANO: MODE_STRING_WEIGHT / MODE_STRING_CLICK. BOWED: MODE_BOW_PIZZ (≥0.5 plucks instead of bows). value 0..1. (decision 0017)\ninstrument_mode(slot, MODE_BOW_PIZZ, 1.0f);  // make a BOWED slot pizzicato' },
  note_aux:     { sig: 'void note_aux(int handle, int idx, float value)',               doc: 'ADVANCED — the per-engine aux channel, LIVE face: a raw per-engine param poke by index on a held note. idx is per-engine; INSTR_VOICE uses the probe carts\' VP_* map (voxlab/voxab/voxpad/say). The everyday VOICE controls are the 3 macros + voice_nasal(); this is the expert hatch beneath them. (decision 0017)\nnote_aux(h, VP_VOWEL, 0.5f);  // poke a raw VOICE param live' },
  MODE_STRING_WEIGHT: { sig: '#define MODE_STRING_WEIGHT 0', doc: 'instrument_mode idx — INSTR_GUITAR/PIANO fundamental-reinforcement weight (0 = pure string .. 1 = body-thick). Read at note-on.\ninstrument_mode(slot, MODE_STRING_WEIGHT, 0.4f);' },
  MODE_STRING_CLICK:  { sig: '#define MODE_STRING_CLICK 1',  doc: 'instrument_mode idx — INSTR_GUITAR/PIANO attack click / pick-noise amount. Read at note-on.\ninstrument_mode(slot, MODE_STRING_CLICK, 0.6f);' },
  MODE_BOW_PIZZ:      { sig: '#define MODE_BOW_PIZZ 0',      doc: 'instrument_mode idx — INSTR_BOWED: ≥0.5 = PIZZICATO (pluck the same string), < 0.5 = arco (bow, self-oscillating hold). Read at note-on.\ninstrument_mode(slot, MODE_BOW_PIZZ, 1.0f);  // pizzicato' },
  note_filter:  { sig: 'void note_filter(int handle, int mode)',                      doc: 'Switch a held note’s filter mode live: FILTER_OFF/LOW/HIGH/BAND/NOTCH/LADDER. Flip from lowpass to bandpass mid-note.\nnote_filter(h, FILTER_BAND);' },
  note_glide:   { sig: 'void note_glide(int handle, int ms)',                          doc: 'Portamento: make this held note SLIDE to new pitches over `ms` instead of snapping. 0 = snap (default). Set it once after note_on, then every note_pitch glides.\nnote_glide(h, 120);  note_pitch(h, 67);' },
  note_duty:    { sig: 'void note_duty(int handle, float duty)',                      doc: 'Change a held note’s pulse width 0.0–1.0 live (pulse/square slots only). Animate it for a PWM shimmer.\nnote_duty(h, 0.5 + sin_deg(now()*180)*0.4);' },
  note_pan:     { sig: 'void note_pan(int handle, float pan)',                        doc: 'Move a held note’s stereo position live: -1 = hard left, 0 = center, +1 = hard right. Slewed (no zipper), so sweep it for a glide across the field. Great for positional audio — map it to where a sprite is on screen.\nnote_pan(h, (px - SCREEN_W/2) / (SCREEN_W/2.0f));  // follow the sprite' },
  note_off_all: { sig: 'void note_off_all(void)',                                     doc: 'Release every held note at once. Handy panic / cleanup if you lost track of a handle.\nnote_off_all();' },

  midi_get:     { sig: 'int midi_get(int *note, int *vel)',                           doc: 'Drain ONE MIDI event from a plugged-in keyboard this frame. Returns +1 (note-on), -1 (note-off), or 0 (none); fills *note (0..127) and *vel (1..127). Call it in a while loop, then play the note yourself.\nmacOS now; desktop Chrome on web later (not Safari/iOS).\nint n, v, t;\nwhile ((t = midi_get(&n, &v)) != 0) {\n  if (t > 0) note(n, 5, v >> 4); else note_off_all();\n}' },
  midi_held:    { sig: 'bool midi_held(int note)',                                    doc: 'Is this MIDI note currently held down? Poll style, like btn() — handy for highlighting keys.\nif (midi_held(60)) print("middle C", 8, 8, CLR_WHITE);' },
  midi_bend:    { sig: 'int midi_bend(void)',                                         doc: 'Last pitch-bend wheel value: -8192..+8191, 0 = centred. Map it onto note_pitch for live bends/ribbons.\nfloat bend = midi_bend() / 8192.0f * 2;  // +/- 2 semitones' },
  midi_present: { sig: 'bool midi_present(void)',                                     doc: 'Is any MIDI keyboard connected? Use it to show a "plug in a keyboard" hint.\nif (!midi_present()) print("connect MIDI", 8, 8, CLR_DARK_GREY);' },
  midi_name:    { sig: 'const char *midi_name(void)',                                 doc: 'Name of the connected MIDI keyboard (e.g. "Arturia KeyStep"), or "" if none. Handy for a "connected to …" readout.\nif (midi_present()) print(str("MIDI: %s", midi_name()), 8, 8, CLR_LIME_GREEN);' },
  instrument:   { sig: 'void instrument(int slot, int wave, int attack_ms, int decay_ms, int sustain, int release_ms)', doc: 'Define an instrument in `slot` (5–47): a waveform shaped by an ADSR envelope. Then play it like any wave with note(midi, slot, vol).\nattack/decay/release in ms, sustain 0–7. Slots 0–4 are the built-in waves.\nwave can be INSTR_SQUARE…INSTR_SINE, or a hand-DRAWN one: INSTR_USER0–3, filled with wave_set() (draw it in the “wave editor” cart).\nPluck: instrument(5, INSTR_SAW, 2, 90, 1, 120).\nPad:   instrument(6, INSTR_SINE, 300, 0, 7, 500).' },
  instrument_duty: { sig: 'void instrument_duty(int slot, float duty)',                doc: 'Set the pulse width of a square-wave instrument slot. 0.5 = full square, 0.12 = thin/nasal, 0.25 = hollow. No effect on saw/tri/sine/noise.\ninstrument_duty(7, 0.12);' },
  instrument_pan: { sig: 'void instrument_pan(int slot, float pan)',                   doc: 'Set the stereo position of an instrument slot: -1 = hard left, 0 = center (default), +1 = hard right. Every note played on the slot inherits it; change a single held note live with note_pan, or sweep it automatically with LFO_PAN. Linear pan law — a centered slot is bit-for-bit the old mono mix, so nothing changes until you actually pan.\ninstrument_pan(SL_HAT, -0.4f);  // hats sit left of center' },
  instrument_level: { sig: 'void instrument_level(int slot, float gain)',              doc: 'Set the output LEVEL of an instrument slot, 0..1 — the per-slot volume trim for balancing a multi-part mix (a kit that’s all one instrument each needs the kick pulled back, the hats up, etc). 1 = unity (default — bit-for-bit the old mix, so nothing changes until you touch it), 0.5 ≈ half, 0 = silent. Read LIVE at mix like instrument_tune, so fire-and-forget hits obey it and you can sweep/automate it (volume swells, ducks). The level leg of the per-slot mixer family alongside instrument_drive/echo/reverb/pan.\ninstrument_level(SL_KICK, 0.8f);  // pull the kick back a touch' },
  mic_start: { sig: 'void mic_start(void)', doc: 'MICROPHONE INPUT (mic-and-sampling.md): ask the host to open the mic so the cart can HEAR — the Tier-1 "mic as a controller" surface. Pops the OS permission prompt the FIRST time (macOS/iOS/web all gate the mic), so call it on a deliberate user action (a button/tap), not every frame. Dormant + byte-identical until called: no capture, no prompt, until a cart asks. Poll mic_active() to know it is really open, then read mic_level() / mic_pitch(). The device + permission live in the platform host; the engine only analyzes the frames it is fed.\nif (keyp(KEY_SPACE)) mic_start();' },
  mic_stop: { sig: 'void mic_stop(void)', doc: 'Release the microphone — the host closes its capture device and mic_level()/mic_pitch() go to 0. Pair with mic_start(); use it when the cart leaves its listening mode so a phone is not holding the mic open (and its indicator on) needlessly.\nmic_stop();' },
  mic_active: { sig: 'int mic_active(void)', doc: 'Returns 1 once capture is actually live AND microphone permission was granted, else 0. Poll it after mic_start(): the open is asynchronous (a permission dialog may be up), and on a denied grant the device can be "open" yet deliver silence — so treat mic_active() as "the mic is on", and mic_level() staying at 0 as "but nothing is coming in".\nif (mic_active()) { /* draw the VU meter */ }' },
  mic_level: { sig: 'float mic_level(void)', doc: 'Current INPUT loudness, 0..1 (RMS over a short window) — the beatbox / envelope-follower input. Solid and responsive: drive a VU meter, trigger on a clap, gate an effect on how loud you are. 0 until mic_active(). For a dB meter use 20*log10f(mic_level()) (about -60..0 dBFS).\nfloat v = mic_level();  rectfill(8, 8, (int)(v * 300), 12, CLR_LIME_GREEN);' },
  mic_pitch: { sig: 'float mic_pitch(void)', doc: 'Pitch of the input in Hz (0 = no clear pitch) — the hum-to-theremin input. A YIN detector (autocorrelation family): tracks a hummed/sung voice cleanly and is OCTAVE-SAFE (none of the octave jumps a zero-crossing estimate makes on a harmonic-rich voice), and reports 0 rather than guessing when the input is unvoiced/too quiet. Updates ~21×/sec (a fresh reading per ~46ms window) — a melody/controller axis (map it to pitch, a filter cutoff, a paddle), not a sample-accurate tuner. 0 until mic_active() and loud enough to trust.\nfloat hz = mic_pitch();  if (hz > 0) note_pitch(voice, 69 + 12*log2f(hz/440.0f));' },
  mic_record: { sig: 'void mic_record(float seconds)', doc: 'Capture up to `seconds` (max 8) of the MIC input into a buffer — the capture-then-freeze move: record a beatboxed loop or a sung phrase, then read it out with mic_record_read() and hand it to sample_load() to chop/play. Needs the mic open first (mic_start + permission). Resets any prior take. Poll mic_recording() for done, then read.\nmic_start();  if (mic_active()) mic_record(4.0f);' },
  mic_recording: { sig: 'int mic_recording(void)', doc: 'Returns 1 while a mic_record() capture is still filling, 0 once the take is complete (or none armed). Gate your read on it: the audio thread is writing the buffer until this goes 0.\nif (!mic_recording()) { int n = mic_record_read(buf, MAX); sample_load(0, buf, n); }' },
  mic_record_progress: { sig: 'float mic_record_progress(void)', doc: 'Capture fill 0..1 during a mic_record() — for drawing a REC progress bar / countdown.\nrectfill(8, 8, (int)(mic_record_progress() * 200), 8, CLR_RED);' },
  mic_record_rate: { sig: 'int mic_record_rate(void)', doc: 'Sample rate (Hz) of the audio captured by mic_record(). On desktop this equals the engine rate (44100) so a sample_load() plays back at true pitch; on a device whose mic runs at another rate the load plays slightly speed-shifted (a later resample is the fix).' },
  mic_record_read: { sig: 'int mic_record_read(float *out, int max)', doc: 'Copy the captured mic PCM (mono, -1..1) into out[] (up to `max` floats); returns the sample count. Call after mic_recording() is 0. Peak-normalize it yourself if you want, then sample_load() it into a slot to play/chop (see breakchop for onset auto-chopping a beatboxed take).\nfloat *b = malloc(sizeof(float)*MAXN); int n = mic_record_read(b, MAXN); sample_load(0, b, n);' },
  record_arm: { sig: 'void record_arm(void)',                                            doc: 'PCM SAMPLER (mic-and-sampling.md): begin the always-on rolling capture of the master output — the console records its OWN sound into a buffer. Idempotent; OFF and byte-identical until you call it (so it never touches carts that don’t sample). Call once (e.g. in init), then record_grab() any time to snapshot the recent audio. The capture ring holds the last ~8 seconds.\nrecord_arm();  // start listening to my own output' },
  record_grab: { sig: 'int record_grab(int sample_slot, float seconds)',                 doc: 'Snapshot the last `seconds` of captured audio into PCM sample slot 0..7 (replacing whatever was there), peak-normalized with leading/trailing SILENCE TRIMMED so the buffer starts at the first audible sample (no dead air from the gap between arming and the first note). Returns the sample count grabbed AFTER trimming (0 = not armed, or nothing captured yet). Then play it back with instrument_sample() + INSTR_SAMPLE. This is the “record what I just played, then play with it” move — the source is the console’s own synthesis, not a mic.\nint n = record_grab(0, 2.0f);  // grab the last 2 seconds into sample slot 0' },
  instrument_sample: { sig: 'void instrument_sample(int slot, int sample_slot, int root_midi)', doc: 'Bind an INSTR_SAMPLE instrument slot to a recorded buffer (from record_grab). root_midi = the note that plays the buffer at its ORIGINAL speed (e.g. 60 = C4); press higher and it plays faster / up in pitch, lower = slower / down — the classic sampler keyboard. Use with a keybed to play your recording chromatically.\ninstrument(5, INSTR_SAMPLE, 1, 0, 7, 200);\ninstrument_sample(5, 0, 60);  // slot 5 plays sample 0, C4 = original pitch' },
  instrument_sample_mode: { sig: 'void instrument_sample_mode(int slot, int mode)', doc: 'Set how an INSTR_SAMPLE slot plays its chop: SAMPLE_NORMAL (one-shot forward), SAMPLE_REVERSE (one-shot backward), SAMPLE_LOOP (forward, wrapping to the chop start — keeps sounding while the note is held), or SAMPLE_PINGPONG (bounce forward/backward between the chop ends while held). Loop/pingpong turn a chop into a sustained pad/texture; normal/reverse are one-shots gated by the amp envelope.\ninstrument_sample_mode(5, SAMPLE_LOOP);' },
  SAMPLE_NORMAL:   { sig: '#define SAMPLE_NORMAL 0',   doc: 'INSTR_SAMPLE playback mode: play the chop once, forward (default). Pass to instrument_sample_mode().' },
  SAMPLE_REVERSE:  { sig: '#define SAMPLE_REVERSE 1',  doc: 'INSTR_SAMPLE playback mode: play the chop once, backward. Pass to instrument_sample_mode().' },
  SAMPLE_LOOP:     { sig: '#define SAMPLE_LOOP 2',     doc: 'INSTR_SAMPLE playback mode: loop the chop forward (wrap to start) — sustains while the note is held. Pass to instrument_sample_mode().' },
  SAMPLE_PINGPONG: { sig: '#define SAMPLE_PINGPONG 3', doc: 'INSTR_SAMPLE playback mode: bounce forward/backward between the chop ends while held. Pass to instrument_sample_mode().' },
  instrument_sample_region: { sig: 'void instrument_sample_region(int slot, float start, float end)', doc: 'Set the CHOP for an INSTR_SAMPLE slot: play the bound buffer only from `start` to `end`, both as fractions 0..1 of the whole recording (default 0,1 = play it all). Move the marks live — e.g. drag two handles on a drawn waveform — to isolate a single slice out of a longer recording. Each new note-on seeks to `start` and stops at `end`.\ninstrument_sample_region(5, 0.25f, 0.5f);  // play just the 2nd quarter of the recording' },
  sample_peaks: { sig: 'int sample_peaks(int slot, float *lo, float *hi, int n)', doc: 'Waveform readout for drawing: downsample PCM sample slot 0..7 into `n` columns, writing the min amplitude of each column to lo[] and the max to hi[] (both -1..1, n floats each). Returns the buffer length in samples (0 = empty slot). Call it at draw time to render the recorded waveform (a filled shape between lo and hi per pixel column), then overlay chop handles.\nfloat lo[240], hi[240];\nint len = sample_peaks(0, lo, hi, 240);\nfor (int x = 0; x < 240; x++) line(x, 100 - hi[x]*40, x, 100 - lo[x]*40, CLR_LIME_GREEN);' },
  sample_read: { sig: 'int sample_read(int slot, float *out, int max)', doc: 'Read a sample slot 0..7’s RAW PCM out (mono, -1..1) into out[], up to `max` floats. Returns the count copied (0 = empty slot). The full-resolution twin of sample_peaks (which only gives min/max for drawing) — use it to SAVE a recorded buffer to disk (save_bytes) or export it. Pair with sample_load() to restore.\nstatic float pcm[330000];\nint n = sample_read(0, pcm, 330000);  // then save_bytes(pcm, n * sizeof(float))' },
  sample_load: { sig: 'void sample_load(int slot, const float *data, int n)', doc: 'Load RAW PCM (mono, -1..1, `n` samples) INTO sample slot 0..7 — the inverse of sample_read, so a buffer saved with save_bytes restores WITHOUT re-recording it (persistence), or you load a WAV. Replaces any prior buffer. No normalization/trim (taken as-is — unlike record_grab). Then instrument_sample()/instrument_sample_region() play it like any grabbed take.\nsample_load(0, pcm, n);\ninstrument(5, INSTR_SAMPLE, 1, 0, 7, 200);  instrument_sample(5, 0, 60);' },
  instrument_playhead: { sig: 'float instrument_playhead(int slot)', doc: 'The live playback position (0..1 of the buffer) of the INSTR_SAMPLE voice currently sounding on instrument `slot`, or -1 if nothing is playing there. Poll it at draw time to paint a moving playhead over the waveform as a chop plays — one per pad slot, or the KEYS voice. Racy read (visual only, no cost to audio).\nfloat p = instrument_playhead(6);\nif (p >= 0) line(PX + (int)(p*PW), PY, PX + (int)(p*PW), PY+PH, CLR_WHITE);' },
  record_peaks: { sig: 'int record_peaks(float seconds, float *lo, float *hi, int n)', doc: 'The LIVE twin of sample_peaks, for the capture ring WHILE you record (before any record_grab). Downsamples the last `seconds` of captured audio into n min/max columns (lo[]/hi[], -1..1). Returns the sample count covered (0 = not armed / nothing yet). Use it with the recording elapsed to draw the take "filling in" as a waveform that matches the grabbed-sample look, instead of a scrolling oscilloscope.\nfloat lo[300], hi[300];\nint cols = (int)(elapsed / 8.0f * 300);\nrecord_peaks(elapsed, lo, hi, cols);  // draw cols columns, growing left→right' },
  pan_law:      { sig: 'void pan_law(int law)',                                        doc: 'Pick how a pan position maps to left/right gain — master-wide, set once in init().\nPAN_LINEAR (default): a centered sound keeps full gain on both channels, bit-for-bit the old mono mix — but center is +3dB louder than a hard pan (a "buildup" in the middle).\nPAN_POWER: constant-power law — center drops to -3dB so a sound feels equally loud anywhere in the field. Smoother, more pronounced movement, at the cost of changing centered output (NOT mono-identical), so only opt in if your cart actually pans.\npan_law(PAN_POWER);  // equal-loudness panning for a heavily-panned cart' },
  listener:      { sig: 'void listener(float x, float y)',                            doc: 'Set where the player’s ears are, in world coordinates. Every positioned sound (note_pos / hit_at) pans and attenuates relative to this. Call it each frame as the player/camera moves. The whole spatial system is dormant — byte-identical to before — until you call this once.\nlistener(player.x, player.y);' },
  listener_vel:  { sig: 'void listener_vel(float vx, float vy)',                       doc: 'Set the listener’s velocity (world units per second) so Doppler works when YOU move past a sound. 0,0 = still (default). Usually the player’s velocity this frame.\nlistener_vel(player.vx, player.vy);' },
  spatial_model: { sig: 'void spatial_model(float ref_dist, float max_dist, float rolloff)', doc: 'Tune the distance→volume falloff. Full volume within ref_dist, fading to silent at max_dist; rolloff sets the steepness (1 = natural inverse-distance). Set once in init(); defaults (~24 / 400 / 1) suit a 320-wide screen.\nspatial_model(16, 300, 1.0f);  // tighter, quieter-with-distance world' },
  spatial_speed: { sig: 'void spatial_speed(float c)',                                 doc: 'Speed of sound in world units/sec — controls Doppler strength. Lower = more dramatic pitch-bend as things fly past; 0 turns Doppler off entirely. Default ~340.\nspatial_speed(200);  // exaggerated whoosh' },
  note_pos:      { sig: 'void note_pos(int handle, float x, float y)',                 doc: 'Place a held note (a note_on handle) at a world position. The engine derives its pan (from bearing) and volume (from distance to the listener) automatically, slewed so motion is smooth. Call each frame as the source moves.\nint h = note_on(48, INSTR_PLUCK, 5);\nnote_pos(h, enemy.x, enemy.y);  // drone follows the enemy' },
  note_motion:   { sig: 'void note_motion(int handle, float vx, float vy)',            doc: 'Give a held note a velocity (world units/sec) so it Dopplers as it moves past the listener — the classic race-car / siren whoosh. Pair with note_pos each frame.\nnote_motion(h, car.vx, car.vy);' },
  hit_at:        { sig: 'void hit_at(int midi, int instr, int vol, int dur_ms, float x, float y)', doc: 'Fire a one-shot note positioned in the world — pan, volume and Doppler are snapshotted at the moment of the hit (no handle to manage). The go-to for positional sound effects: a gunshot, an impact, a footstep over there.\nhit_at(40, INSTR_NOISE, 6, 120, explosion.x, explosion.y);' },
  instrument_pos:    { sig: 'void instrument_pos(int slot, float x, float y)', doc: 'Position an instrument’s WHOLE effected output in the world — dry voices PLUS its FX tail (shimmer/reverb/echo). The entire produced sound pans and attenuates as one object, so a shimmered pad or a radio mix moves with its tail intact. (note_pos positions dry voices only; their wet tail stays put — this fixes that.) Give the instrument a per-instrument effect first (e.g. instrument_shimmer) so there IS a tail to move; call each frame as the source moves.\ninstrument_shimmer(5, 0.85f, 0.4f, 0.5f, 0.4f);\ninstrument_pos(5, radio.x, radio.y);' },
  instrument_motion: { sig: 'void instrument_motion(int slot, float vx, float vy)', doc: 'Give a positioned instrument bus a velocity (world units/sec) so the WHOLE effected source Dopplers as it passes the listener — tail and all (the radio-driving-past whoosh). Pairs with instrument_pos each frame.\ninstrument_motion(5, radio.vx, radio.vy);' },
  PAN_LINEAR:   { sig: '#define PAN_LINEAR 0', doc: 'pan_law() option: linear pan — center keeps full gain (L=R=mix), byte-identical to mono. Center is +3dB vs hard-panned. The default; leave it unless panning sounds uneven.' },
  PAN_POWER:    { sig: '#define PAN_POWER 1',  doc: 'pan_law() option: constant-power pan — center is -3dB, equal perceived loudness right across the sweep. Smoother panning, but NOT mono-identical (it shifts centered output), so opt in only when the cart pans.' },
  instrument_lfo: { sig: 'void instrument_lfo(int slot, int which, int dest, float rate_hz, float depth)', doc: 'Attach a slow LFO to an instrument, wobbling a parameter over time. A slot has 3 LFOs — `which` is 0, 1, or 2 — so you can vibrato AND sweep a filter at once. dest picks what each moves:\nLFO_PITCH = vibrato (depth in semitones), LFO_DUTY = PWM shimmer (square only), LFO_VOLUME = tremolo, LFO_CUTOFF = filter sweep/wah (depth in Hz).\nrate is the wobble speed in Hz (4–8 is typical). depth 0 = off. The waveform defaults to sine — change it with lfo_shape() (e.g. S&H on pitch = a random-step arp).\ninstrument_lfo(5, 0, LFO_PITCH, 6, 0.3);  // gentle vibrato on LFO 0' },
  lfo_shape: { sig: 'void lfo_shape(int slot, int which, int shape)', doc: 'Set the WAVEFORM of a slot\'s LFO `which` (0–2) to an LFO_SHAPE_* (default SINE). Separate from instrument_lfo() so it stays non-breaking; persists across instrument_lfo() retunes. The expressive ones: LFO_SHAPE_SH on LFO_PITCH = a random-step arp; LFO_SHAPE_SQUARE on LFO_CUTOFF = a stepped two-state filter; LFO_SHAPE_RANDOM = a drifting, human wander.\ninstrument_lfo(5, 0, LFO_PITCH, 8, 7);\nlfo_shape(5, 0, LFO_SHAPE_SH);  // random-step arp' },
  note_lfo_shape: { sig: 'void note_lfo_shape(int handle, int which, int shape)', doc: 'Set a live held note\'s LFO `which` waveform to an LFO_SHAPE_* — the note_lfo() twin of lfo_shape(). Change a ringing voice\'s vibrato into a square trill or a random wander.\nnote_lfo_shape(h, 0, LFO_SHAPE_TRI);' },
  lfo_value: { sig: 'float lfo_value(int shape, float phase)', doc: 'Evaluate an LFO_SHAPE_* at `phase` (0..1, wraps) → -1..1, using the ENGINE\'s own shape dispatcher. Use it to drive your own CV/modulation or draw a waveform without re-implementing the math (e.g. a modular LFO module, a viz trace). STATELESS shapes only (SINE/SQUARE/TRI/SAW/RAMP/OPTICAL); S&H and RANDOM need per-instance state, so they read as SINE here — use a voice/effect LFO (lfo_shape/fx_lfo) for those.\nfloat cv = (lfo_value(LFO_SHAPE_TRI, t) + 1) * 0.5f;  // 0..1' },
  scope_read: { sig: 'void scope_read(float *dst, int n)', doc: 'OSCILLOSCOPE: copy the latest `n` mono output samples (newest last, range -1..1) into `dst` — the ACTUAL post-FX master mix, not a prediction. For drawing a live waveform: watch the ladder round a saw\'s corners, watch DRIVE_ASYM flatten one side. `n` is clamped to 2048; `dst` must hold `n` floats. The raw window scrolls; to "freeze" the trace, scan dst for a rising zero-crossing and draw starting from there. Zero cost / byte-identical until the first call (the tap is gated).\nfloat buf[512]; scope_read(buf, 512);\nfor (int x = 1; x < 512; x++) line(x-1, 100 - buf[x-1]*40, x, 100 - buf[x]*40, CLR_LIME_GREEN);' },
  scope_read2: { sig: 'void scope_read2(float *l, float *r, int n)', doc: 'STEREO scope: copy the latest `n` LEFT and RIGHT output samples (newest last, same-index pairs) into `l`/`r` — the vectorscope/goniometer feed. Plot mid=(L+R) vertical vs side=(L-R) horizontal: a mono mix draws a vertical line, autopan tilts it side to side, chorus/reverb open it into a cloud. `n` is clamped to 2048; each buffer must hold `n` floats. Zero cost / byte-identical until the first call (the tap is gated — separate from scope_read\'s).\nfloat L[512], R[512]; scope_read2(L, R, 512);\nfor (int i = 0; i < 512; i++) pset(160 + (int)((L[i]-R[i])*40), 100 - (int)((L[i]+R[i])*40), CLR_LIME_GREEN);' },
  LFO_PITCH:    { sig: '#define LFO_PITCH 0',  doc: 'LFO target: pitch → vibrato. depth is in semitones (0.3 subtle, 2 wide).' },
  LFO_DUTY:     { sig: '#define LFO_DUTY 1',   doc: 'LFO target: pulse width → PWM shimmer. Square-wave slots only. depth 0.0..0.5.' },
  LFO_VOLUME:   { sig: '#define LFO_VOLUME 2', doc: 'LFO target: volume → tremolo. depth 0.0..1.0 (how deep it dips).' },
  LFO_CUTOFF:   { sig: '#define LFO_CUTOFF 3', doc: 'LFO target: filter cutoff → sweep/wah. depth in Hz. Needs a filter on the slot.' },
  LFO_HARMONICS:{ sig: '#define LFO_HARMONICS 4', doc: 'LFO target: the harmonics macro (engine voices, INSTR_PLUCK+). SNAPPED — the LFO STEPS through the engine’s detents (wavetype/ratio/instrument): a wavetype sequencer on PD, jarring on EP. depth 0..1.' },
  LFO_TIMBRE:   { sig: '#define LFO_TIMBRE 5', doc: 'LFO target: the timbre macro (engine voices). Continuous → smooth brightness wobble; on a PD resonant wavetype it sweeps the resonant peak — a filter sweep with no filter. depth 0..1.' },
  LFO_MORPH:    { sig: '#define LFO_MORPH 6', doc: 'LFO target: the morph macro (engine voices) — the engine’s 3rd axis (PD DCW depth, FM feedback, organ chorus, EP bark). depth 0..1.' },
  LFO_PAN:      { sig: '#define LFO_PAN 7', doc: 'LFO target: stereo position → auto-pan. depth 0..1 (1 = full left↔right sweep). The declarative way to get rotary/tremolo-pan motion; rate ~0.2–2 Hz for a slow drift, faster for a wobble.\ninstrument_lfo(5, 0, LFO_PAN, 0.5, 1.0);  // a slow full-width pan' },
  LFO_DETUNE:   { sig: '#define LFO_DETUNE 8', doc: 'LFO target: the unison spread → a breathing/chorusing width wobble. depth in semitones. Needs instrument_unison() on the slot (no effect otherwise). rate ~0.1–1 Hz for a slow analog drift.\ninstrument_lfo(5, 0, LFO_DETUNE, 0.3, 0.2);  // the wall gently breathes' },
  instrument_filter: { sig: 'void instrument_filter(int slot, int mode, int cutoff_hz, int resonance)', doc: 'Run an instrument through a resonant filter — the tone-sculpting knob.\nmode: FILTER_LOW (warm), FILTER_HIGH (thin), FILTER_BAND (vowel), FILTER_NOTCH (phasey), FILTER_LADDER (the fat 24dB Moog lowpass), FILTER_DIODE (the 303 acid squelch), FILTER_STEINER (the aggressive one).\ncutoff in Hz (try 400–2000). resonance 0–15 — high adds a whistly peak at the cutoff.\nSweep the cutoff for a wah with instrument_lfo(slot, LFO_CUTOFF, 0.5, 800).\ninstrument_filter(5, FILTER_LOW, 800, 10);' },
  instrument_env: { sig: 'void instrument_env(int slot, int which, int dest, int attack_ms, int decay_ms, float amount)', doc: 'Attach a one-shot AD envelope to an instrument — the envelope twin of instrument_lfo(). Fires once per note: ramps up over attack_ms, then decays back over decay_ms. A slot has 3 (`which` 0, 1, or 2), so a filter sweep, a pitch blip, AND a PWM sweep can run together. dest picks what it moves; `amount` is bipolar, units depend on dest:\nENV_CUTOFF = filter sweep, the pluck “pew” (amount in Hz, needs a filter), ENV_PITCH = pitch blip / drum punch (amount in semitones), ENV_DUTY = PWM sweep (amount 0..1).\namount 0 = off. (There is no ENV_VOLUME — that’s the amp envelope, instrument().)\ninstrument_env(5, 0, ENV_CUTOFF, 0, 120, 1500);  // pluck filter snap' },
  instrument_follow: { sig: 'void instrument_follow(int slot, int dest, int attack_ms, int release_ms, float amount)', doc: 'Envelope FOLLOWER — the third modulation source (after the LFO and mod-envelope). It tracks the slot’s OWN amplitude with a fast attack + slow release, so the modulation responds to how hard/much you play. dest reuses LFO_CUTOFF / LFO_VOLUME / LFO_PITCH; amount in Hz for cutoff (0 = off).\nThe touch-responsive auto-wah: a resonant bandpass + a follower opening its cutoff = the funky envelope filter (Mu-Tron). Play harder → it opens wider; it “hangs” on the release.\ninstrument_filter(5, FILTER_BAND, 400, 12);  instrument_follow(5, LFO_CUTOFF, 3, 200, 1800);' },
  note_follow:  { sig: 'void note_follow(int handle, int dest, int attack_ms, int release_ms, float amount)', doc: 'Set a held note’s envelope follower live — same shape as instrument_follow() but on a ringing voice. dest LFO_CUTOFF/VOLUME/PITCH; amount 0 = off.\nnote_follow(h, LFO_CUTOFF, 3, 200, 1800);' },
  instrument_harmonics: { sig: 'void instrument_harmonics(int slot, float x)',        doc: 'Engine macro 1 of 3 — every modeled engine (INSTR_PLUCK, INSTR_MALLET, INSTR_FM, …) answers the SAME three 0..1 knobs: harmonics / timbre / morph. What each sweeps is per-engine, but the API never grows when a new engine lands (the Plaits/MicroFreak discipline).\nFor PLUCK: ring time — 0 = dead slap, 1 = near-endless sustain. For MALLET: bar material — 0 = wood (marimba), 1 = metal/bell. For FM: carrier:modulator ratio, snapped to musical detents — integers = harmonic (bass/epiano/brass), off-integers = bells, the top = the DX tine. For GUITAR: body — 0 = open & bodyless (harp), 1 = resonant bright box (banjo). For PIANO: voicing — snaps across grand / bright / harpsichord / dulcimer / clavichord / celesta. For BRASS: instrument/bore — 0 = tight bright trumpet → 1 = dark wide tuba. Default 0.5.\ninstrument_harmonics(5, 0.85f);  // long singing ring (PLUCK)' },
  instrument_timbre: { sig: 'void instrument_timbre(int slot, float x)',              doc: 'Engine macro 2 of 3 (0..1) — see instrument_harmonics() for the three-knob idea.\nFor PLUCK: pick brightness — 0 = soft felt/thumb thud, 1 = hard bright pick. For MALLET: mallet hardness — 0 = soft yarn (pure fundamental thump), 1 = hard brass (bright + contact click). For FM: brightness (FM amount) — decays within each note like a real DX strike. For GUITAR: string brightness — 0 = warm nylon, 1 = bright steel. For PIANO: hammer — 0 = soft felt/mellow, 1 = hard/bright plectrum. For BRASS: brassiness — 0 = round & mellow, 1 = loud & blatty (the shockwave overtone explosion). Default 0.5.\ninstrument_timbre(5, 0.2f);  // soft nylon feel' },
  instrument_morph: { sig: 'void instrument_morph(int slot, float x)',                doc: 'Engine macro 3 of 3 (0..1) — see instrument_harmonics() for the three-knob idea.\nFor PLUCK: pick position — 0 = near the bridge (full, every harmonic), 1 = mid-string (hollow, flute-like). For MALLET: ring length — 0 = dry tick (xylophone), 1 = long vibraphone sustain; the top third fades the motor tremolo in. For FM: modulator feedback — 0 = clean, up = saw-edge growl, top = noisy clang. For GUITAR: mute — 0 = long open ring, 1 = tight muted pizzicato stop. For PIANO: pedal — 0 = dry/damped staccato, 1 = long open sustain. For BRASS: breath/lip lean-in — 0 = soft steady, 1 = a growling breath with deeper vibrato. Default 0.5.\ninstrument_morph(5, 0.9f);  // hollow harp tone (PLUCK)' },
  instrument_choke: { sig: 'void instrument_choke(int slot_a, int slot_b)',           doc: 'Declare a choke: a new note on slot_a instantly kills any sounding voice on slot_b. The classic use is the TR-808 hat — closed hat chokes the open hat so it can\'t ring through.\nCall once in init() after defining both slots.\ninstrument_choke(SL_HATC, SL_HATO);  // closed hat chokes open hat' },
  instrument_tune: { sig: 'void instrument_tune(int slot, float semitones)',          doc: 'Detune a slot ±24 semitones — fractions are the point: 0.06 on one slot of a pad pair = unison shimmer, ±1 = a tuning trimmer (the SH-101 TUNE knob). LIVE: every sounding voice on the slot bends with the call, scheduled arp/seq hits included — the one pitch control that reaches fire-and-forget notes. 0 = off (default).\ninstrument_tune(6, 0.06f);  // detune pad slot 6 against its twin' },
  instrument_sync: { sig: 'void instrument_sync(int slot, float ratio)',     doc: 'Oscillator HARD SYNC on a wavetable slot (SAW/SQUARE/TRI/SINE/USER). A second “slave” oscillator runs at ratio×the played pitch and is force-reset to the start of its cycle every time the master cycle completes — the discontinuity makes the bright, tearing, vocal tone. The played PITCH stays the master’s; ratio is the TIMBRE. 0 = off (default), 1 = unison (transparent), 1.5–4 = the classic sync sound. SWEEP it (note_sync, or a slow LFO) for the screaming sync lead. Naive (aliases like the rest of the oscillators).\ninstrument_sync(5, 2.0f);' },
  instrument_unison: { sig: 'void instrument_unison(int slot, int voices, float detune)',  doc: 'UNISON: one slot renders `voices` (1..7) slightly-detuned copies of its own oscillator, summed — the JP-8000 Super Saw wall, the fat analog poly. The beating between the copies is the life. `voices` applies at the NEXT note (structural, like the waveform); `detune` (spread in semitones — 0.1 shimmer, 0.4 fat, 0.7 wide) rides LIVE. Loudness-normalized (character, not volume). Wavetable slots only (SAW/SQUARE/TRI/SINE); takes precedence over hard sync. 1 = off (default).\ninstrument_unison(5, 7, 0.3f);  // a 7-saw supersaw lead' },
  instrument_unison_detune: { sig: 'void instrument_unison_detune(int slot, float detune)',  doc: 'Ride the unison spread alone, LIVE — the detune-BLOOM gesture: 0 = a thin single oscillator, wider = the wall opens into N voices. Set the stack with instrument_unison() first, then sweep this by hand, or drive it declaratively with LFO_DETUNE (breathing wobble) / ENV_DETUNE (the attack bloom). Motion-recordable.\ninstrument_unison_detune(5, bloom * 0.6f);' },
  note_sync:       { sig: 'void note_sync(int handle, float ratio)',          doc: 'Sweep a held note’s hard-sync ratio live (slewed, zipper-free) — the sync sweep under your fingers. Pairs with instrument_sync(); ride it with an envelope/LFO for the iconic lead.\nnote_sync(h, 1.0f + env*3.0f);' },
  instrument_drive: { sig: 'void instrument_drive(int slot, float x)',                doc: 'Overdrive an instrument slot 0..1 — saturation applied AFTER the filter, so a resonant peak screams into it (the 303 squelch recipe: FILTER_LOW + high resonance + drive). 0 = clean (default, a true bypass), 0.2–0.4 = warm thickening, 0.7+ = fuzz. Loudness stays put — full-scale stays full-scale while quiet detail comes up, so it changes character, not volume.\ninstrument_drive(5, 0.35f);  // warm gritty bass' },
  note_drive:   { sig: 'void note_drive(int handle, float x)',                        doc: 'Sweep a held note’s drive 0..1 live, slewed (no zipper) — the held-voice twin of instrument_drive(). Ride it up together with note_cutoff/note_res for the acid scream.\nnote_drive(h, lever);' },
  instrument_drive_mode: { sig: 'void instrument_drive_mode(int slot, int mode)',      doc: 'Pick the drive waveshaper for a slot — the *flavour* of grit (instrument_drive() is still the *amount*). DRIVE_SOFT (default, tanh — warm overdrive), DRIVE_HARD (square-edged digital fuzz), DRIVE_FOLD (metallic sine wavefolder), DRIVE_ASYM (asymmetric tube — adds even harmonics, the fat round one). All four are a true bypass at drive 0.\ninstrument_drive_mode(5, DRIVE_ASYM);\ninstrument_drive(5, 0.5f);' },
  note_drive_mode: { sig: 'void note_drive_mode(int handle, int mode)',                doc: 'Switch a held note’s drive waveshaper live (DRIVE_*). Snaps (the flavour is an enum, not a slewable value) — sweep instrument_drive()/note_drive() for the amount.\nnote_drive_mode(h, DRIVE_FOLD);' },
  DRIVE_SOFT: { sig: '#define DRIVE_SOFT 0', doc: 'instrument_drive_mode() flavour: tanh soft-clip — warm, tube-like overdrive. The default (what drive did before modes existed).' },
  DRIVE_HARD: { sig: '#define DRIVE_HARD 1', doc: 'instrument_drive_mode() flavour: hard clip — buzzy, square-edged digital fuzz. The harshest.' },
  DRIVE_FOLD: { sig: '#define DRIVE_FOLD 2', doc: 'instrument_drive_mode() flavour: sine wavefolder — metallic, glassy, ring-mod-ish as you push the amount up.' },
  DRIVE_ASYM: { sig: '#define DRIVE_ASYM 3', doc: 'instrument_drive_mode() flavour: asymmetric tube — adds EVEN harmonics (the round, fat, single-ended-amp grit). Asymmetry grows with the amount.' },
  echo:         { sig: 'void echo(int time_ms, float feedback, float tone)',          doc: 'Configure THE echo bus — there is exactly one, shared by every slot (a delay line is big; one tempo’d echo per song is the musical truth anyway). time_ms 1..2000 = delay per repeat (tempo-sync it yourself: 60000/bpm*0.75 = dotted-8th). feedback 0..1.1 = how much each repeat feeds the next — past 1.0 it SELF-OSCILLATES into a tape-style saturation instead of exploding. tone 0..1 = repeats get darker (0) or stay bright (1) each pass.\nSweeping time_ms live pitch-bends the ringing tail like varying tape speed.\nDefaults: 375ms, 0.35, 0.5 — instrument_echo() alone already sounds right.\necho(450, 0.55f, 0.3f);  // dark dub tail' },
  instrument_echo: { sig: 'void instrument_echo(int slot, float send)',               doc: 'How much this slot feeds the echo bus, 0..1. 0 = fully dry (default — old carts unchanged), 0.1–0.2 = slapback presence, 0.5+ = dub territory. The dry signal always stays at full volume; send only controls the wet copy.\ninstrument_echo(SL_LEAD, 0.18f);  // slapback on the lead only' },
  note_echo:    { sig: 'void note_echo(int handle, float x)',                         doc: 'Sweep a held note’s echo send 0..1 live, slewed — the held-voice twin of instrument_echo(). The signature dub move: crank it on one phrase, drop it back, and that phrase alone rings out in the tail.\nnote_echo(h, 0.9f);  // throw this note into the echo' },
  echo_insert:  { sig: 'void echo_insert(int time_ms, float feedback, float tone, float mix)', doc: 'Echo as a dry/wet INSERT on the master bus — a REAL reorderable DELAY pedal, unlike echo() (a parallel send whose chain position is cosmetic). Put FX_ECHO in your fx_order(0, …) list to set WHERE it sits, then placing it before/after another pedal is audible (delay→drive = the repeats distort; drive→delay = clean echoes of a distorted signal). time_ms 1..2000 (delay per repeat), feedback 0..1.1 (past 1 self-oscillates into tape saturation), tone 0..1 (darker→brighter repeats), mix 0..1 (0 = bypass; the repeats sit on top of the full dry). Master only.\nint chain[] = { FX_CRUSH, FX_ECHO };  echo_insert(375, 0.45f, 0.5f, 0.4f);  fx_order(0, chain, 2);' },
  drive_insert: { sig: 'void drive_insert(float amount, int mode, float mix)', doc: 'MIX-BUS SATURATION — drive the whole summed mix as a reorderable INSERT (the bus sibling of per-voice instrument_drive). Where per-voice drive sits post-filter inside one voice (resonance screams into it — the 303/acid trick), this saturates the SUMMED bus: tube/tape glue at gentle settings, a lo-fi wall when cranked, and it grits the drums too. Reuses the DRIVE_* shaper curves so it A/Bs against per-voice drive. Put FX_DRIVE in your fx_order(0, …) list to set WHERE it sits (before vs after crush/echo is audible). amount 0..1 (clean→fuzz), mode DRIVE_SOFT/HARD/FOLD/ASYM, mix 0..1 (0 = bypass → byte-identical). Master only.\nint chain[] = { FX_DRIVE, FX_REVERB };  drive_insert(0.4f, DRIVE_ASYM, 0.6f);  fx_order(0, chain, 2);' },
  drive_insert_inst: { sig: 'void drive_insert_inst(int instance, float amount, int mode, float mix)', doc: 'A 2nd mix-bus drive INSTANCE (Increment F) so two bus drives can sit at different chain spots — e.g. an overdrive pedal feeding the amp\'s own drive. instance 0 == drive_insert(). Pair with FX_INST(FX_DRIVE, instance) in fx_order().\ndrive_insert_inst(1, 0.5f, DRIVE_SOFT, 1.0f);' },
  grains:       { sig: 'void grains(float grain_ms, float density, float position, float scatter, float feedback, float mix)', doc: 'Granular delay — captures the live signal into a buffer, then sprays scattered, overlapping windowed GRAINS of the recent past into an evolving cloud (a navkit port). The texture/ambient pedal: feed it a rich source (held chords, pads) and it blooms. grain_ms 5..1000 (grain length — short = shimmery, long = smeared), density 1..100 grains/sec (sparse → dense wash), position 0..1 (0 = grab from deep in the past, 1 = near the live edge), scatter 0..1 (random spread around position — the "evolving" knob), feedback 0..0.95 (output re-fed into the buffer → self-sustaining cloud), mix 0..1 (0 = off). A reorderable insert (FX_GRAINS), auto-placed on first call. Pair with grains_freeze() to hold a moment forever.\ngrains(120, 12, 0.8f, 0.3f, 0.2f, 0.5f);  // classic shimmer cloud' },
  instrument_grains: { sig: 'void instrument_grains(int slot, float grain_ms, float density, float position, float scatter, float feedback, float mix)', doc: 'Granular cloud on just ONE instrument (its own FX bus) — grain the pads while the drums stay dry. Same args as grains() plus the slot. A small pool means the master grains() plus ONE instrument can run at once.\ninstrument_grains(SL_PAD, 200, 20, 0.6f, 0.5f, 0.4f, 0.6f);' },
  grains_freeze: { sig: 'void grains_freeze(int on)', doc: 'Freeze the master granular buffer: stop capturing new audio and loop what is already there FOREVER (1 = frozen, 0 = live). The performance move — play a chord, freeze it into an infinite shimmering pad, then solo over the cloud. Does not reconfigure the DSP, so it is safe to toggle live.\ngrains_freeze(1);  // hold this moment' },
  instrument_grains_freeze: { sig: 'void instrument_grains_freeze(int slot, int on)', doc: 'Freeze one instrument\'s granular buffer (1 = frozen, 0 = live). Per-instrument version of grains_freeze().\ninstrument_grains_freeze(SL_PAD, 1);' },
  grains_pitch: { sig: 'void grains_pitch(float semitones, float spread, int reverse)', doc: 'Transpose the master grain cloud — turns granular delay into a glitch/shimmer machine. semitones -24..24 (12 = an octave up, -12 = down); the Hanning window stays the same length so it is a true pitch-shift, not a speed change. spread 0..1 = random per-grain detune → from unison to a shimmering chord-cloud. reverse 1 = grains play backwards through the buffer (the classic reverse-grain wash). Call grains() first (it allocates the cloud); grains_pitch() modifies it. Cheap to sweep live — automate semitones for a rising/falling cloud.\ngrains(120, 18, 0.7f, 0.4f, 0.3f, 0.6f);  grains_pitch(12, 0.2f, 0);  // octave-up shimmer' },
  instrument_grains_pitch: { sig: 'void instrument_grains_pitch(int slot, float semitones, float spread, int reverse)', doc: 'Transpose one instrument grain cloud (per-instrument grains_pitch). Same args + a slot.\ninstrument_grains_pitch(SL_PAD, -12, 0.3f, 1);  // octave-down reverse cloud on the pad' },
  reverb:       { sig: 'void reverb(float size, float damping)',                       doc: 'Configure THE reverb bus — there is exactly one, shared by every slot (a real room/hall, not repeating taps like echo). size 0..1 = small room → endless cathedral (decay length). damping 0..1 = how dark the tail gets (0 = bright/glassy, 1 = warm/muffled). Bus-only — reverb is never a per-voice effect.\nDefaults size 0.5 / damping 0.5 — instrument_reverb() alone already sounds like a good room.\nreverb(0.9f, 0.3f);  // big bright cathedral' },
  instrument_reverb: { sig: 'void instrument_reverb(int slot, float send)',            doc: 'How much this slot feeds the reverb bus, 0..1. 0 = fully dry (default — old carts unchanged), 0.3 = roomy, 0.8 = drenched. The dry signal always stays at full volume; send only controls the wet copy that blooms into the hall.\ninstrument_reverb(SL_PAD, 0.6f);  // wash the pad in reverb' },
  note_reverb:  { sig: 'void note_reverb(int handle, float x)',                         doc: 'Sweep a held note’s reverb send 0..1 live, slewed — the held-voice twin of instrument_reverb(). Bloom a single sustained chord into the hall, then pull it back dry.\nnote_reverb(h, 0.8f);  // send this note into the room' },
  reverb_bus:   { sig: 'void reverb_bus(int tank, float size, float damp)',             doc: 'Make reverb tank 1 or 2 into an independent reverb SPACE on its own bus — so two instruments can sit in two different rooms at once (drums tight / keys vast), AND you can run effects AFTER the reverb. size 0..1 (room→hall), damp 0..1 (bright→dark). Claims an aux bus on first call; reverb_bus_fx(tank, …) then adds effects after the reverb (a crushed / EQ’d tail). Tank 0 is reverb()’s master send — use 1..2 here.\nreverb_bus(1, 0.9f, 0.4f);  // tank 1 = a big plate' },
  instrument_reverb_bus: { sig: 'void instrument_reverb_bus(int slot, int tank, float mix)', doc: 'Route this slot’s reverb send into a reverb_bus() tank (1..2) instead of the shared master send — the slot now blooms into THAT space. mix 0..1 = how drenched. Configure the space with reverb_bus(tank, …) first.\ninstrument_reverb_bus(SL_DRUMS, 1, 0.5f);  // drums → tank 1’s room' },
  reverb_bus_fx: { sig: 'void reverb_bus_fx(int tank, int fx, float a, float b, float c)', doc: 'Run an effect AFTER the reverb on a reverb_bus() tank (1..2) — a crushed / EQ’d / tape-warmed / chorused TAIL (the wet rings, then the pedal chews it). fx = FX_CRUSH (a=bits 1..16, b=rate 1..64, c=mix; mix 0 = off) · FX_EQ (a/b/c = low/mid/high dB ±12) · FX_TAPE (a/b/c = wow/flutter/sat 0..1) · FX_CHORUS (a=rate, b=depth, c=mix). Effects stack in call order. Needs reverb_bus(tank,…) first.\nreverb_bus_fx(2, FX_CRUSH, 5, 8, 1.0f);  // lo-fi crushed plate tail' },
  reverb_insert: { sig: 'void reverb_insert(float size, float damp, float mix)', doc: 'Reverb as a dry/wet INSERT on the master bus — a REAL reorderable pedal, unlike reverb() (a parallel send whose chain position is cosmetic). Put FX_REVERB in your fx_order(0, …) list to set WHERE it sits, then dragging it before/after another pedal is audible (reverb→crush vs crush→reverb). size 0..1, damp 0..1, mix 0..1 (0 = bypass, all dry). This is what makes a pedalboard reverb honest.\nint chain[] = { FX_EQ, FX_REVERB, FX_CRUSH };  reverb_insert(0.7f, 0.3f, 0.4f);  fx_order(0, chain, 3);' },
  chorus:       { sig: 'void chorus(float rate, float depth, float mix)',                doc: 'Configure THE master chorus — there is exactly one, applied to the whole mix. A BBD/Juno-style modulated delay that thickens and WIDENS everything into a lush stereo shimmer (the antiphase taps fan a mono mix out across the stereo field — the Juno’s “two amps”). Distinct from instrument_tune detune: this is the swirling string-machine/Juno chorus, not just unison thickening. rate 0.1..5 = wobble speed (Hz). depth 0..1 = sweep amount. mix 0..1 = dry..wet (0 = off). Master-wide; per-part chorus waits for bus routing.\nDefaults 1.5 / 0.4 / 0.5 — a gentle Juno wash.\nchorus(0.8f, 0.5f, 0.5f);  // lush slow Solina shimmer' },
  flanger:      { sig: 'void flanger(float rate, float depth, float feedback, float mix)',  doc: 'Configure THE master flanger — there is exactly one, applied to the whole mix. A SHORT swept delay (0.1–10ms) with feedback: the sweeping comb-filter notches give the jet-plane whoosh and metallic resonance. Cousin of chorus (same modulated-delay technique) but shorter + fed back. rate 0.05..5 = sweep speed (Hz). depth 0..1 = sweep range. feedback -0.95..0.95 = the jet/metallic intensity (more = stronger resonance; negative = through-zero, deeper). mix 0..1 = dry..wet (0 = off). Needs a rich source (chords / noise) to hear — a sine barely flanges.\nDefaults 0.3 / 0.7 / 0.7 / 0.5 — the classic jet.\nflanger(0.2f, 0.8f, 0.85f, 0.5f);  // slow deep jet sweep' },
  instrument_chorus: { sig: 'void instrument_chorus(int slot, float rate, float depth, float mix)',  doc: 'Chorus on just ONE instrument (slot), not the whole mix — flange/chorus the pad while drums + bass stay dry. Same params as chorus() plus the slot. The slot gets its own private FX bus the first time you call this (chorus + flanger on the same slot chain together). Up to 7 instruments can have their own inserts at once; beyond that, extra ones stay dry. (echo/reverb are already per-instrument via instrument_echo/instrument_reverb.)\ninstrument_chorus(SL_PAD, 0.8f, 0.5f, 0.5f);  // lush Solina pad, rest of the mix clean' },
  instrument_flanger: { sig: 'void instrument_flanger(int slot, float rate, float depth, float feedback, float mix)',  doc: 'Flanger on just ONE instrument (slot) — flange the guitar, leave the rhythm dry. Same params as flanger() plus the slot; the slot grabs a private FX bus on first use. Up to 7 per-instrument inserts at once.\ninstrument_flanger(SL_GUITAR, 0.3f, 0.7f, 0.7f, 0.6f);  // jet on the lead only' },
  tape:         { sig: 'void tape(float wow, float flutter, float saturation)',           doc: 'Configure THE master tape — vintage analog warmth over the whole mix: wow = slow pitch DRIFT (the seasick warble), flutter = fast pitch warble, saturation = warm soft-clip + a gentle HF rolloff (tape loses highs). The third use of the modulated-delay technique (cousin of chorus/flanger). All 0..1 (0,0,0 = off). Most audible on sustained pitched material (you hear the warble) + full mixes (the warmth/glue).\nDefaults 0.3 / 0.2 / 0.4 — tasteful vintage.\ntape(0.5f, 0.3f, 0.6f);  // wonky warm cassette' },
  instrument_tape: { sig: 'void instrument_tape(int slot, float wow, float flutter, float saturation)',  doc: 'Tape (wow/flutter/saturation) on just ONE instrument (slot) — lo-fi just the drums, warm just the pad. Same params as tape() plus the slot; the slot grabs a private FX bus on first use.\ninstrument_tape(SL_DRUMS, 0.4f, 0.5f, 0.7f);  // wonky lo-fi drums, rest clean' },
  wah:          { sig: 'void wah(float sensitivity, float resonance, float mix)',                   doc: 'Configure THE master auto-wah — a resonant bandpass whose cutoff OPENS with how hard you play (an envelope follower tracks the summed signal). The funky "talking" wah quack. Unlike a per-note filter sweep, this tracks the whole performance, so a chord opens coherently and it pumps with the groove. sensitivity 0..1 = how much dynamics open it. resonance 0..1 = the quack (Q). mix 0..1 = dry..wet (0 = off). Best on ONE rich/percussive instrument (a clav, a funk guitar) — use instrument_wah for that.\nDefaults 0.5 / 0.5 / 0.7.\nwah(0.6f, 0.7f, 0.8f);  // funk-clav quack' },
  instrument_wah: { sig: 'void instrument_wah(int slot, float sensitivity, float resonance, float mix)',  doc: 'Auto-wah on just ONE instrument (slot) — the classic funk-clavinet / wah-guitar move: the filter opens on the hard stabs and quacks shut between them, the rest of the mix dry. Same params as wah() plus the slot; the slot grabs a private FX bus on first use.\ninstrument_wah(SL_CLAV, 0.6f, 0.7f, 0.85f);  // talking clavinet' },
  wah_lfo:      { sig: 'void wah_lfo(float rate_hz, float resonance, float mix)',                        doc: 'THE master wah swept by an LFO instead of a follower — same resonant bandpass, rocked by a sine at `rate_hz`. The RHYTHMIC "wah-wah-wah" (moves on a clock, regardless of how you play), vs wah()\'s dynamics-following quack. rate 0.5..10 Hz. resonance 0..1 = the quack. mix 0..1 (0 = off).\nwah_lfo(2.0f, 0.7f, 1.0f);' },
  instrument_wah_lfo: { sig: 'void instrument_wah_lfo(int slot, float rate_hz, float resonance, float mix)',  doc: 'LFO-swept auto-wah on just ONE instrument — the rhythmic "wah-wah" on one slot (a funk clav, a wah guitar), the rest of the mix dry. Same params as wah_lfo() plus the slot; the slot grabs a private FX bus on first use.\ninstrument_wah_lfo(SL_CLAV, 2.0f, 0.7f, 1.0f);' },
  crush:        { sig: 'void crush(float bits, float rate, float mix)',                              doc: 'Configure THE master bitcrush — lo-fi quantization on the whole mix: drop the bit depth and the sample rate for crunchy 8-bit / retro grit. bits 1..16 = bit depth (low = gnarlier, steppy quantization noise; 16 ≈ clean). rate 1..64 = sample-rate reduction (sample-and-hold every `rate` samples — high = more aliasing whine + that downsampled sound). mix 0..1 = dry..wet (0 = off). For ONE instrument use instrument_crush instead.\nDefaults 8 / 4 / 1.0.\ncrush(6.0f, 8.0f, 1.0f);  // gritty downsampled mix' },
  crush_inst:   { sig: 'void crush_inst(int instance, float bits, float rate, float mix)',  doc: 'A 2nd master bitcrush INSTANCE (Increment F) so two crushers can sit at different chain spots (instance 0 == crush()). List FX_INST(FX_CRUSH, instance) in fx_order().\ncrush_inst(1, 4.0f, 8.0f, 1.0f);' },
  tape_inst:    { sig: 'void tape_inst(int instance, float wow, float flutter, float saturation)',  doc: 'A 2nd master tape INSTANCE (Increment F); instance 0 == tape(). Pair with FX_INST(FX_TAPE, instance) in fx_order().\ntape_inst(1, 0.4f, 0.2f, 0.5f);' },
  filter_inst:  { sig: 'void filter_inst(int instance, int mode, float cutoff_hz, float resonance)',  doc: 'A 2nd master filter INSTANCE (Increment F) — filter A/B in one chain; instance 0 == filter(). Pair with FX_INST(FX_FILTER, instance) in fx_order().\nfilter_inst(1, FILTER_HIGH, 800.0f, 0.4f);' },
  instrument_crush: { sig: 'void instrument_crush(int slot, float bits, float rate, float mix)',      doc: 'Bitcrush on just ONE instrument (slot) — crush the drums to 8-bit while the synths stay clean, or grit up a single lead. Same params as crush() plus the slot; the slot grabs a private FX bus on first use.\ninstrument_crush(SL_DRUMS, 5.0f, 6.0f, 1.0f);  // 8-bit drums, rest hi-fi' },
  eq:           { sig: 'void eq(float low_gain, float mid_gain, float high_gain)',                   doc: 'Configure THE master EQ — a 3-band tone control on the whole mix that can BOOST as well as cut (the only effect that can; the filters only cut). low_gain shapes the lows (<~80 Hz — weight/body/sub), mid_gain the mids (~80 Hz–6 kHz — the meat of most sounds), high_gain the highs (>~6 kHz — presence/air). All in dB, ±12 (+ = boost, − = cut, 0 = flat). 0/0/0 = off (byte-identical to no EQ). Pair with DRIVE_ASYM (EQ around a clipper) for a real guitar-amp tone. For ONE instrument use instrument_eq instead.\neq(4.0f, -2.0f, -3.0f);  // +4 lows, scooped mids, −3 highs' },
  instrument_eq: { sig: 'void instrument_eq(int slot, float low_gain, float mid_gain, float high_gain)',  doc: 'EQ on just ONE instrument (slot) — boost a bass’s low end, scoop a guitar’s mids, add air to a lead, the rest of the mix untouched. 3 bands (low/mid/high), same as eq() plus the slot; the slot grabs a private FX bus on first use.\ninstrument_eq(I_BASS, 6.0f, 0.0f, 0.0f);  // fat bass, nothing else changed' },
  eq_inst:      { sig: 'void eq_inst(int instance, float low_gain, float mid_gain, float high_gain)',  doc: 'Configure a SECOND master EQ (instance 0 or 1) so you can run two EQs in one chain — the classic EQ before AND after a dirt stage (shape the input vs the output). instance 0 == eq(). Same 3 bands / ±12 dB. List FX_INST(FX_EQ, instance) in fx_order() to place each one.\neq(4,0,0); eq_inst(1, 0,0,-6);\nint chain[] = { FX_EQ, FX_CRUSH, FX_INST(FX_EQ,1) };  fx_order(0, chain, 3);' },
  FX_INST:      { sig: '#define FX_INST(kind, inst) ((kind) | ((inst) << 4))',  doc: 'Tag an FX_* kind with an INSTANCE for fx_order(), so the same effect can appear twice in one chain at different positions. Configure instance n with eq_inst(n,…). Plain FX_* = instance 0.\nFX_INST(FX_EQ, 1)' },
  formant:      { sig: 'void formant(float vowel, float q, float mix)',                                doc: 'Configure THE master formant (vowel) filter — four bandpasses parked at the human vowel frequencies, so the whole mix takes on an "ooh/aah/eee" vocal colour (the talkbox/vowel filter; a wah is the one-peak version of this). vowel 0..1 sweeps OO→OH→AH→EH→EE; sweep it and a synth "talks". q 0..1 = how pronounced/nasal the peaks are. mix 0..1 = dry..wet (0 = off). A single-input filter — NOT a vocoder (that needs a second carrier×modulator input). For ONE instrument use instrument_formant.\nformant(0.5f, 0.6f, 0.9f);  // an "AH" on the whole mix' },
  instrument_formant: { sig: 'void instrument_formant(int slot, float vowel, float q, float mix)',     doc: 'Formant (vowel) filter on just ONE instrument (slot) — make a pad/lead/drum loop "sing" a vowel while the rest of the mix stays plain. Same params as formant() plus the slot; the slot grabs a private FX bus on first use. Sweep vowel for a talkbox effect on that part alone.\ninstrument_formant(I_PAD, 0.75f, 0.7f, 0.85f);  // a vowel-singing pad' },
  filter:       { sig: 'void filter(int mode, float cutoff_hz, float resonance)',                         doc: 'Configure THE master resonant FILTER — a sweepable state-variable filter on the whole mix: the DJ-filter / build-up sweep. mode = FILTER_LOW (muffle — the classic), FILTER_HIGH (thin it out), FILTER_BAND, FILTER_NOTCH, or FILTER_OFF (bypass). cutoff_hz 20..~20000 — RIDE it: close it to a few hundred Hz for the breakdown thump, open it back up for the build/drop. resonance 0..1 = the peak at the cutoff (crank it for the screaming acid/build resonance). A reorderable insert (FX_FILTER), and unlike the buffer effects it is cheap to call every frame — sweep it live.\nfilter(FILTER_LOW, 400.0f, 0.7f);  // breakdown: muffled + resonant' },
  sidechain:    { sig: 'void sidechain(int victim_bus, int key, float amount, int attack_ms, int release_ms)', doc: 'SIDECHAIN compression on the SUMMED signal — the house/EDM "pump": duck a victim bus\'s level every time a TRIGGER fires. victim_bus 0 = the master mix (the usual). key 0..3 = which trigger drives it; route a slot (the kick) into that key with sidechain_key(). amount 0..1 = how hard it ducks (0 = off, byte-identical). attack_ms fast (~1) so it grabs the transient, release_ms slow (~80–250) so the mix breathes back across the beat. A gain stage, NOT a chain insert — it is not in fx_order.\nsidechain_key(SL_KICK, 0, 1.0f);  sidechain(0, 0, 0.6f, 1, 140);  // pad+bass pump to the kick' },
  sidechain_key: { sig: 'void sidechain_key(int slot, int key, float send)',                            doc: 'Route an instrument (slot) into a sidechain TRIGGER key 0..3 — its level becomes the trigger for any sidechain() keyed there. The kick is the classic trigger → key 0. send 0..1 (0 = not a trigger). The slot still plays normally; this just also taps its level into the key bus.\nsidechain_key(SL_KICK, 0, 1.0f);  // the kick drives trigger key 0' },
  glue:         { sig: 'void glue(int victim_bus, float amount, int attack_ms, int release_ms)',         doc: 'BUS COMPRESSOR — the same gain stage as sidechain() but with NO external trigger: it ducks victim_bus from its OWN level, so the whole mix "breathes as one lump" (the mix-glue / drum-bus squash). victim_bus 0 = master. amount 0..1 (0 = off). attack ~5–10ms, release ~150ms for gentle glue.\nglue(0, 0.4f, 8, 150);  // gentle master-bus glue' },
  vocoder:      { sig: 'void vocoder(float mix)', doc: 'VOCODER (docs/design/vocoder.md) — a synth "speaks" in another sound\'s voice: carrier × modulator cross-synthesis on the master. The CARRIER is the whole master mix (play a rich, broadband source — a SAW/pulse CHORD, not a sine); the MODULATOR is whatever slot(s) you vocoder_send() (a voice / INSTR_VOICE line / drum loop). 12 log-spaced bands: each modulator band\'s loudness shapes the matching carrier band, so the carrier takes on the modulator\'s spectral envelope (its "words"/rhythm). mix 0..1 wet (0 = off, byte-identical). Output is MONO. A master gain stage, not an fx_order insert.\ninstrument(5, INSTR_SAW, 8,120,7,200); note_on(48,5,6); note_on(55,5,6);  // carrier chord\ninstrument(6, INSTR_VOICE, 5,80,7,150); vocoder_send(6, 1.0f);  note_on(60,6,6);  // modulator\nvocoder(0.9f);' },
  vocoder_send: { sig: 'void vocoder_send(int slot, float amount)', doc: 'Route instrument `slot` into the VOCODER MODULATOR (amount 0..1). SEND-ONLY: the slot\'s own DRY output is muted — it is heard only through the way it shapes the carrier. Use it on the "talking" source (a voice line, a drum loop, later the mic). 0 = not a modulator. Pair with vocoder().\nvocoder_send(6, 1.0f);  // slot 6 becomes the modulator (its dry is silenced)' },
  tremolo:      { sig: 'void tremolo(float rate, float depth, int shape)',                            doc: 'Configure THE master tremolo — a volume LFO that ducks the whole mix up and down: the Fender/Wurlitzer amp wobble, the "electric piano" throb. rate 0.1..20 Hz (wobble speed), depth 0..1 (how deep it ducks; 0 = off), shape = any LFO_SHAPE_* (TREM_SINE smooth default / SQUARE hard chop / TRI ramp / plus SAW/RAMP/OPTICAL/SH/RANDOM). Only attenuates, never boosts — like a real amp. For ONE instrument use instrument_tremolo.\ntremolo(5.5f, 0.5f, TREM_SINE);  // a classic EP throb' },
  instrument_tremolo: { sig: 'void instrument_tremolo(int slot, float rate, float depth, int shape)',  doc: 'Tremolo on just ONE instrument (slot) — wobble the EP/organ’s volume while the rest of the mix stays steady. One shared LFO phase across all the slot’s notes, so the whole instrument throbs in unison (the coherent amp wobble a per-voice LFO_VOLUME can’t give — there each note has its own phase). Same params as tremolo() plus the slot; grabs a private FX bus on first use.\ninstrument_tremolo(I_EP, 6.0f, 0.6f, TREM_SINE);  // the Wurlitzer 200A throb' },
  autopan:      { sig: 'void autopan(float rate, float depth, int shape)',                            doc: 'Configure THE master auto-pan — the tremolo LFO applied ANTIPHASE to the L/R channels, so the whole mix sweeps side to side (the Rhodes suitcase vibrato; rotary-style motion). rate 0.1..20 Hz (sweep speed), depth 0..1 (0 = off, 1 = full L↔R), shape = any LFO_SHAPE_* (TREM_SINE smooth default / SQUARE hard ping-pong / TRI sweep / plus SAW/RAMP/OPTICAL/SH/RANDOM). It’s its OWN insert, so it STACKS with tremolo on the same bus — a fast throb AND a slow stereo drift at once. For ONE instrument use instrument_autopan.\nautopan(2.0f, 1.0f, TREM_SINE);  // a slow full-width stereo sweep' },
  instrument_autopan: { sig: 'void instrument_autopan(int slot, float rate, float depth, int shape)',  doc: 'Auto-pan on just ONE instrument (slot) — sweep that instrument’s stereo position while the rest of the mix stays put. The bus-level antiphase tremolo, so the whole instrument incl. its tails pans coherently (unlike the per-voice LFO_PAN, where each note has its own phase). Same params as autopan() plus the slot; grabs a private FX bus on first use.\ninstrument_autopan(I_EP, 3.0f, 0.8f, TREM_SINE);  // the Rhodes Suitcase stereo vibrato' },
  ringmod:      { sig: 'void ringmod(float freq_hz, float mix)',                                       doc: 'Configure THE master ring modulator — multiply the whole mix by a sine CARRIER at freq_hz, creating inharmonic sum/difference sidebands: the metallic, clangorous, robotic/bell texture (the Dalek voice, the sci-fi clang). Unlike tremolo (a unipolar gain LFO that just wobbles volume), the carrier is BIPOLAR, so it adds NEW frequencies. freq 1..8000 Hz (low ~2..30 Hz = a throbby AM; high ~100..2000 Hz = atonal clang), mix 0..1 (0 = off). |out| never exceeds |in|, so no added clip risk. For ONE instrument use instrument_ringmod.\nringmod(440.0f, 0.8f);  // a metallic clang on the whole mix' },
  instrument_ringmod: { sig: 'void instrument_ringmod(int slot, float freq_hz, float mix)',           doc: 'Ring mod on just ONE instrument (slot) — make one part metallic/robotic while the rest of the mix stays clean. Same params as ringmod() plus the slot; grabs a private FX bus on first use.\ninstrument_ringmod(I_LEAD, 300.0f, 0.7f);  // a clangy robot lead' },
  LFO_SHAPE_SINE:    { sig: '#define LFO_SHAPE_SINE 0',    doc: 'LFO waveform: smooth sine — the default everywhere. Used by lfo_shape()/note_lfo_shape()/fx_lfo() and tremolo()/autopan().\nlfo_shape(5, 0, LFO_SHAPE_SINE);' },
  LFO_SHAPE_SQUARE:  { sig: '#define LFO_SHAPE_SQUARE 1',  doc: 'LFO waveform: hard on/off square. On LFO_CUTOFF = a stepped two-state filter; on volume = a chop/stutter gate. (= TREM_SQUARE.)\nlfo_shape(5, 0, LFO_SHAPE_SQUARE);' },
  LFO_SHAPE_TRI:     { sig: '#define LFO_SHAPE_TRI 2',     doc: 'LFO waveform: linear triangle up/down — sharper than sine. (= TREM_TRI.)\nfx_lfo(0, FXMOD_FILTER_CUT, 0.3f, 0.4f, 0.5f, LFO_SHAPE_TRI);' },
  LFO_SHAPE_SAW:     { sig: '#define LFO_SHAPE_SAW 3',     doc: 'LFO waveform: sawtooth — ramps DOWN then snaps up (1→-1). A repeating fall/decay sweep.\nlfo_shape(5, 0, LFO_SHAPE_SAW);' },
  LFO_SHAPE_RAMP:    { sig: '#define LFO_SHAPE_RAMP 4',    doc: 'LFO waveform: reverse saw — ramps UP then snaps down (-1→1). A repeating rise/swell sweep.\nlfo_shape(5, 0, LFO_SHAPE_RAMP);' },
  LFO_SHAPE_OPTICAL: { sig: '#define LFO_SHAPE_OPTICAL 5', doc: 'LFO waveform: the asymmetric incandescent-bulb throb (slow brighten, fast dim) — the Univibe glow; liquid where a sine is even.\nfx_lfo(0, FXMOD_FILTER_CUT, 4.0f, 0.5f, 0.5f, LFO_SHAPE_OPTICAL);' },
  LFO_SHAPE_SH:      { sig: '#define LFO_SHAPE_SH 6',      doc: 'LFO waveform: sample & hold — a random value, stepped once per cycle and held. On LFO_PITCH = a random-step arpeggio; on LFO_CUTOFF = a per-step filter jump. Deterministically seeded (--det safe).\ninstrument_lfo(5,0,LFO_PITCH,8,7); lfo_shape(5,0,LFO_SHAPE_SH);' },
  LFO_SHAPE_RANDOM:  { sig: '#define LFO_SHAPE_RANDOM 7',  doc: 'LFO waveform: smooth filtered random walk — a drifting, "human" wander (not stepped like S&H). Great for subtle living detune/cutoff drift. Deterministically seeded.\nlfo_shape(5, 0, LFO_SHAPE_RANDOM);' },
  TREM_SINE:    { sig: '#define TREM_SINE 0',   doc: 'Tremolo shape: smooth sine wobble — the classic amp / electric-piano tremolo. The default. Alias of LFO_SHAPE_SINE (tremolo()/autopan() accept any LFO_SHAPE_*).\ntremolo(5.5f, 0.5f, TREM_SINE);' },
  TREM_SQUARE:  { sig: '#define TREM_SQUARE 1', doc: 'Tremolo shape: hard on/off chop — the helicopter / stutter gate.\ntremolo(8.0f, 0.9f, TREM_SQUARE);' },
  TREM_TRI:     { sig: '#define TREM_TRI 2',    doc: 'Tremolo shape: linear ramp up/down — sharper than a sine, softer than a square.\ntremolo(5.0f, 0.6f, TREM_TRI);' },
  phaser:       { sig: 'void phaser(float rate, float depth, float feedback, float mix, int stages)',                            doc: 'Configure THE master phaser — a chain of allpass filters swept by an LFO carves moving NOTCHES in the spectrum: the 70s electric-piano / Small Stone swirl (vocal, hollow — softer + rounder than a flanger\'s metallic comb). rate 0..10 Hz (sweep speed; ~0.3–1 for the classic slow swirl), depth 0..1 (how far the notches travel), feedback -0.95..0.95 (resonance around the notches), mix 0..1 (0 = off), stages 2..8 (number of notches — 4 = the classic Phase-90, more = thicker). For ONE instrument use instrument_phaser.\nphaser(0.4f, 0.7f, 0.4f, 0.5f, 4);  // a slow Rhodes swirl' },
  instrument_phaser: { sig: 'void instrument_phaser(int slot, float rate, float depth, float feedback, float mix, int stages)',  doc: 'Phaser on just ONE instrument (slot) — swirl the Rhodes while the bass/drums stay dry. Same params as phaser() plus the slot; grabs a private FX bus on first use. The 70s electric-piano signature.\ninstrument_phaser(I_EP, 0.4f, 0.7f, 0.4f, 0.5f, 4);  // phased Rhodes' },
  univibe: { sig: 'void univibe(float rate, float depth, float mix)', doc: 'The 60s photocell VIBE (Univibe/Shin-ei) — the phaser\'s allpass chain swept by an OPTICAL LFO instead of a sine. The lamp brightens slowly then dims fast, so the sweep is asymmetric and LIQUID where a sine phaser is even and clinical. Classic 4-stage, no feedback. Shares the phaser insert (don\'t run phaser() and univibe() on the same bus). Gorgeous on organ, electric piano, and clean chord work — the Machine Gun / Bridge of Sighs wobble. rate 0..10 Hz (throb speed), depth 0..1 (sweep width), mix 0..1 (0 = off).\nunivibe(4.0f, 0.7f, 0.5f);  // slow liquid vibe' },
  instrument_univibe: { sig: 'void instrument_univibe(int slot, float rate, float depth, float mix)', doc: 'Univibe on just ONE instrument (slot) — vibe the organ, leave the rhythm section dry. Same params as univibe() plus the slot; grabs a private FX bus on first use.\ninstrument_univibe(I_ORGAN, 5.0f, 0.8f, 0.5f);' },
  shallow: { sig: 'void shallow(float rate, float depth, float mix)', doc: 'Shallow water (Fairfield) — a filtered-random "K-field" short delay + a Low Pass Gate. A random WALK (not a sine LFO) drifts the delay time, so the pitch wobbles gently and UNPREDICTABLY — the warped-tape / reflection-on-moving-water shimmer that periodic modulation can\'t fake. Then a Buchla-style Low Pass Gate opens cutoff AND level together: quiet passages go dark + soft and bloom back as they swell (the "underwater" close). A reorderable insert (FX_SHALLOW). Gorgeous on pads, electric piano, and clean guitar. rate 0.2..8 Hz (how fast the drift wanders), depth 0..1 (warble amount), mix 0..1 (0 = off).\nshallow(1.0f, 0.6f, 0.5f);  // a slow watery drift' },
  instrument_shallow: { sig: 'void instrument_shallow(int slot, float rate, float depth, float mix)', doc: 'Shallow water on just ONE instrument (slot) — warble the pad, leave the rest dry. Same params as shallow() plus the slot; grabs a private FX bus on first use.\ninstrument_shallow(I_PAD, 0.8f, 0.7f, 0.6f);' },
  gate: { sig: 'void gate(float threshold, int attack_ms, int release_ms)', doc: 'A NOISE GATE — an envelope follower + threshold that clamps the signal shut when it falls below `threshold` and opens above it. The classic rig pedal: tame the hiss/hum and ringing tails of a noisy or high-gain part between notes. Place it AFTER reverb in fx_order() for the iconic 80s GATED REVERB — the lush tail chops off abruptly (the Phil Collins snare). threshold 0..1 (0 = always open / bypass, byte-identical; higher = closes sooner), attack_ms (how fast it opens on a hit, ~1–10), release_ms (how fast it closes / cuts the tail, ~30–300). A reorderable insert (FX_GATE); master or per-instrument.\ngate(0.4f, 3, 80);  // tighten a noisy part\nint chain[] = { FX_REVERB, FX_GATE };  reverb_insert(0.9f, 0.3f, 0.6f);  gate(0.3f, 2, 120);  fx_order(0, chain, 2);  // gated reverb' },
  instrument_gate: { sig: 'void instrument_gate(int slot, float threshold, int attack_ms, int release_ms)', doc: 'Noise gate on just ONE instrument (slot) — gate the noisy lead, leave the rest open. Same params as gate() plus the slot; grabs a private FX bus on first use.\ninstrument_gate(I_LEAD, 0.4f, 3, 100);' },
  shimmer: { sig: 'void shimmer(float size, float damp, float shimmer_amt, float mix)', doc: 'A SHIMMER REVERB — a reverb with an OCTAVE-UP pitch-shifter inside its feedback loop. Each pass, the wet tail is tapped, pitched up an octave, and re-injected, so the reverb keeps climbing into a glassy, ascending crystalline pad (the Strymon BlueSky / Eno shimmer). Hold a chord and it blooms upward forever. The pitch-shifter is a 2-grain overlap-add octave-up; its gentle granular warble is part of the sound. A master-stage whole-mix space. size 0..1 (decay length), damp 0..1 (darker tail), shimmer_amt 0..1 (how much octave-up recirculates — 0 = a plain reverb, 1 = a wall of ascending crystal), mix 0..1 (0 = off). Gorgeous on pads, organ, bowed strings, held vocals.\nshimmer(0.85f, 0.4f, 0.6f, 0.5f);  // hold a chord and let it rise' },
  instrument_shimmer: { sig: 'void instrument_shimmer(int slot, float size, float damp, float shimmer_amt, float mix)', doc: 'Shimmer reverb on just ONE instrument\'s bus instead of the whole mix — shimmer the pad, leave the drums dry. Same args as shimmer() plus the slot; the slot claims a private aux tank on first use. A small pool means the master shimmer() (bus 0) plus ONE instrument can run at once. Composes with the spatial system: the dry source still pans/Dopplers (at mix<1 the dry keeps its position) while the wash sits as an ambient tail. (Making the wet tail move WITH the source is spatial v2 emitter buses — separate work.)\ninstrument_shimmer(SL_PAD, 0.85f, 0.4f, 0.5f, 0.4f);  // shimmered pad, dry drums' },
  varispeed: { sig: 'void varispeed(float speed)', doc: 'Variable TAPE playback speed of the whole mix (the Chase Bliss MOOD "clock" / a tape-stop dive). Writes the final output to a buffer and reads it back at `speed`: 1.0 = normal (bypass, byte-identical), <1 = slower (pitch DOWN + time-stretch — the tape-slowdown / turntable-brake dive), >1 = faster (chipmunk, pitch up). 0.25..4 = two octaves down to two up. The applied speed GLIDES (tape inertia, no zipper), so SWEEP it: drop to ~0.3 for a tape-stop dive, sweep back to 1.0 to spin back up. Built for sweeps — holding a fixed off-speed eventually laps the buffer (a ~2s click), it is not a sustained pitch shift. Master output stage; dormant (byte-identical) at 1.0.\nvarispeed(0.5f);  // half-speed dive; sweep back to 1.0f to recover' },
  fx_mod: { sig: 'void fx_mod(int bus, int target, float value)', doc: 'MODULATE a sweep-safe effect param from your own control signal — the per-frame CV sink (modrack patches a CV node into this). Configure the effect first (filter()/drive_insert()/grains()/shimmer()/tremolo()/autopan()); fx_mod() RIDES one of its params on top, like LFO_TIMBRE rides an instrument macro. bus 0 = master, 1.. = an instrument\'s bus. target = an FXMOD_* constant. value 0..1, mapped per target (FILTER_CUT is exponential 40Hz..18kHz). Call it every frame with your LFO/envelope/sequencer value — the engine SLEWS internally so per-frame pokes don\'t zipper. Only cheap-to-sweep params are exposed, so it can never reconfigure a buffer effect into a stutter.\nfx_mod(0, FXMOD_FILTER_CUT, 0.5f + 0.5f*sinf(t));  // hand-driven filter wobble' },
  instrument_fx_mod: { sig: 'void instrument_fx_mod(int slot, int target, float value)', doc: 'Like fx_mod() but addressed by INSTRUMENT SLOT instead of bus number — resolves the slot to its private FX bus, then rides the same FXMOD_* target. Use when you\'ve put an effect on one instrument (instrument_filter/_drive/_grains/_shimmer) and want to modulate just that.\ninstrument_fx_mod(SL_PAD, FXMOD_SHIMMER_MIX, env);' },
  fx_lfo: { sig: 'void fx_lfo(int bus, int target, float rate_hz, float depth, float center, int shape)', doc: 'Attach an ENGINE LFO to a sweep-safe effect param — fire-and-forget (no per-frame fx_mod() calls; the LFO runs on the audio thread). Configure the effect first, then: bus (0 = master), target = FXMOD_*, rate_hz (LFO speed), depth 0..1 (peak deviation around center; 0 = DETACH, freezing the param), center 0..1 (the midpoint), shape = an LFO_SHAPE_* (SINE/SQUARE/SAW/SH/…). depth 0.5 + center 0.5 = a full 0..1 swing. Set once; call again to retune; call with depth 0 to detach.\nfx_lfo(0, FXMOD_FILTER_CUT, 0.3f, 0.4f, 0.5f, LFO_SHAPE_SINE);  // slow auto-wah-ish filter sweep' },
  amp_noise: { sig: 'void amp_noise(float hiss, float hum, int mains_hz)', doc: 'An OPTIONAL rig-noise floor — the "an electric guitar is never truly silent" character: broadband HISS (amp/tube thermal noise) + 50/60 Hz mains HUM (the single-coil buzz). Entirely opt-in: hiss 0 AND hum 0 = silent and byte-identical (a fantasy console is pristine by default — you add the grime only when you want it). A constant master-output floor (added after the limiter, so it never ducks or clips with the mix); stereo-decorrelated hiss for width + a centered mono hum. For realism, scale hiss up with your amp\'s gain (hotter amp = more hiss). Pair with a noise gate to clamp it between notes. NOT dither — the hiss + hum are modelled directly. hiss 0..1, hum 0..1, mains_hz 50 (EU) or 60 (US).\namp_noise(0.3f, 0.2f, 60);  // a quietly humming tube amp' },
  dropout: { sig: 'void dropout(float amount, float depth)', doc: 'The VHS / Generation-Loss "FAILURE" knob — random momentary TAPE-CATCHES on the whole mix: the signal stumbles (drops in level AND goes dull from HF loss), then recovers fast. A sample-&-hold clock fires the catches at random; `amount` 0..1 sets how OFTEN the tape stumbles, `depth` 0..1 how HARD (level dip + how dull). A master-stage effect — pair it with crush() + tape() + filter() for the full degraded-cassette sound. amount 0 = off (byte-identical). (Pitch-dip on a catch comes with the bus pitch-shifter later; v1 is level + tone.)\ncrush(6, 4, 0.4f);  tape(0.3f, 0.2f, 0.4f);  dropout(0.4f, 0.7f);  // broken cassette' },
  leslie:       { sig: 'void leslie(int speed, float drive, float balance, float doppler, float mix)',                            doc: 'Configure THE master Leslie — a rotary-speaker cabinet (the classic organ voice): a spinning treble HORN (pitch wobble via Doppler + a swirling volume) over a bass DRUM. The two rotors spin at independent speeds and take seconds to spin up/down when you change speed — the iconic chorale↔tremolo swell. speed = LESLIE_STOP / LESLIE_SLOW (chorale) / LESLIE_FAST (tremolo), drive 0..1 (tube preamp grit), balance 0=drum..0.5=equal..1=horn, doppler 0..1 (horn pitch-wobble depth), mix 0..1 (0 = off). For ONE instrument use instrument_leslie.\nleslie(LESLIE_SLOW, 0.2f, 0.5f, 0.7f, 1.0f);  // then flip to LESLIE_FAST for the swell' },
  instrument_leslie: { sig: 'void instrument_leslie(int slot, int speed, float drive, float balance, float doppler, float mix)',  doc: 'Leslie rotary speaker on just ONE instrument (slot) — spin the organ through its cabinet while the bass/drums stay dry. Same params as leslie() plus the slot; grabs a private FX bus on first use. Flip speed LESLIE_SLOW↔LESLIE_FAST live for the signature swell.\ninstrument_leslie(I_ORGAN, LESLIE_FAST, 0.3f, 0.5f, 0.8f, 1.0f);' },
  LESLIE_STOP:  { sig: '#define LESLIE_STOP 0', doc: 'Leslie speed: brake — the rotors coast to a halt (a static, slightly-doubled tone).\nleslie(LESLIE_STOP, 0.0f, 0.5f, 0.7f, 1.0f);' },
  LESLIE_SLOW:  { sig: '#define LESLIE_SLOW 1', doc: 'Leslie speed: chorale — slow, gentle, hymn-like sway (~0.7 Hz).\nleslie(LESLIE_SLOW, 0.0f, 0.5f, 0.7f, 1.0f);' },
  LESLIE_FAST:  { sig: '#define LESLIE_FAST 2', doc: 'Leslie speed: tremolo — fast, shimmering swirl (~6 Hz). Flip SLOW↔FAST for the iconic spin-up swell.\nleslie(LESLIE_FAST, 0.0f, 0.5f, 0.7f, 1.0f);' },
  fx_order:     { sig: 'void fx_order(int bus, const int *kinds, int n)',  doc: 'Set the ORDER the insert effects run in, for one bus — so you can put bitcrush BEFORE vs AFTER eq (audibly different), or build a reorderable pedalboard. bus 0 = the master mix; 1.. = an instrument’s private FX bus (the one instrument_chorus/eq/… grab). kinds[] is your order, from FX_TREM / FX_WAH / FX_CHORUS / FX_PHASER / FX_FLANGER / FX_TAPE / FX_EQ / FX_CRUSH (+ FX_REVERB, but only on a reverb_bus() bus); n = how many (≤ 9). Kinds you leave out just don’t run. The echo send is parallel, not part of the chain.\nint chain[] = { FX_EQ, FX_CRUSH };  fx_order(0, chain, 2);  // eq THEN crush, on the master' },
  FX_TREM:      { sig: '#define FX_TREM 0',    doc: 'Insert kind: tremolo. Pass to fx_order() to place it in a bus’s chain.\nFX_TREM' },
  FX_WAH:       { sig: '#define FX_WAH 1',     doc: 'Insert kind: auto-wah. Pass to fx_order().\nFX_WAH' },
  FX_CHORUS:    { sig: '#define FX_CHORUS 2',  doc: 'Insert kind: chorus. Pass to fx_order().\nFX_CHORUS' },
  FX_PHASER:    { sig: '#define FX_PHASER 3',  doc: 'Insert kind: phaser. Pass to fx_order().\nFX_PHASER' },
  FX_FLANGER:   { sig: '#define FX_FLANGER 4', doc: 'Insert kind: flanger. Pass to fx_order().\nFX_FLANGER' },
  FX_TAPE:      { sig: '#define FX_TAPE 5',    doc: 'Insert kind: tape. Pass to fx_order().\nFX_TAPE' },
  FX_EQ:        { sig: '#define FX_EQ 6',      doc: 'Insert kind: EQ. Pass to fx_order().\nFX_EQ' },
  FX_CRUSH:     { sig: '#define FX_CRUSH 7',   doc: 'Insert kind: bitcrush. Pass to fx_order().\nFX_CRUSH' },
  FX_REVERB:    { sig: '#define FX_REVERB 8',  doc: 'Insert kind: reverb. ONLY does anything on a reverb_bus() send-bus (a no-op anywhere else). Put it first in that bus’s fx_order() chain, then add pedals after it for reverb→effect.\nint chain[] = { FX_REVERB, FX_CRUSH };  // crushed reverb tail' },
  FX_FORMANT:   { sig: '#define FX_FORMANT 9', doc: 'Insert kind: formant/vowel filter. Pass to fx_order().\nFX_FORMANT' },
  FX_FILTER:    { sig: '#define FX_FILTER 10', doc: 'Insert kind: resonant filter (the DJ filter). Pass to fx_order().\nFX_FILTER' },
  FX_PAN:       { sig: '#define FX_PAN 11',    doc: 'Insert kind: auto-pan (antiphase tremolo). Pass to fx_order() to place it in a bus’s chain — it can sit alongside FX_TREM.\nFX_PAN' },
  FX_RINGMOD:   { sig: '#define FX_RINGMOD 12', doc: 'Insert kind: ring modulator (signal × sine carrier). Pass to fx_order() to place it in a bus’s chain.\nFX_RINGMOD' },
  FX_ECHO:      { sig: '#define FX_ECHO 13',   doc: 'Insert kind: in-line delay (the echo_insert() DELAY pedal). Master only. Pass to fx_order(0, …) to place it — its position vs the other pedals is audible.\nFX_ECHO' },
  FX_GRAINS:    { sig: '#define FX_GRAINS 14', doc: 'Insert kind: granular delay (the grains() texture/freeze cloud). Auto-placed on first grains() call; pass to fx_order() to reposition it in a bus\'s chain.\nFX_GRAINS' },
  FX_SHALLOW:   { sig: '#define FX_SHALLOW 16', doc: 'Insert kind: shallow water (the shallow() K-field delay + Low Pass Gate). Auto-placed on first shallow() call; pass to fx_order() to reposition it. (Kind 16 — the first past the old 16-kind ceiling.)\nFX_SHALLOW' },
  FX_GATE:      { sig: '#define FX_GATE 17', doc: 'Insert kind: noise gate (the gate() follower+threshold). Auto-placed on first gate() call; put it AFTER FX_REVERB in fx_order() for gated reverb.\nFX_GATE' },
  FX_DRIVE:     { sig: '#define FX_DRIVE 15', doc: 'Insert kind: mix-bus saturation (the drive_insert() pedal). Master only. Pass to fx_order(0, …) to place it — before vs after crush/echo is audible. The last kind that fits fx_order\'s 4-bit-per-slot packing (0..15).\nFX_DRIVE' },
  FXMOD_FILTER_CUT:  { sig: '#define FXMOD_FILTER_CUT 0',  doc: 'fx_mod()/fx_lfo() target: the filter() cutoff, mapped exponentially 40Hz..18kHz (THE DJ-filter sweep). Call filter() first to engage the filter, then ride it.\nfx_lfo(0, FXMOD_FILTER_CUT, 0.3f, 0.4f, 0.5f);' },
  FXMOD_FILTER_RES:  { sig: '#define FXMOD_FILTER_RES 1',  doc: 'fx_mod()/fx_lfo() target: the filter() resonance 0..1.\nfx_mod(0, FXMOD_FILTER_RES, 0.7f);' },
  FXMOD_DRIVE:       { sig: '#define FXMOD_DRIVE 2',        doc: 'fx_mod()/fx_lfo() target: the drive_insert() amount 0..1 (lovely wobbling under a slow LFO). Needs drive_insert() with mix>0 first.\nfx_lfo(0, FXMOD_DRIVE, 0.2f, 0.3f, 0.5f);' },
  FXMOD_TREM_DEPTH:  { sig: '#define FXMOD_TREM_DEPTH 3',   doc: 'fx_mod()/fx_lfo() target: the tremolo() depth 0..1 (modulate how deep the tremolo bites).\nfx_mod(0, FXMOD_TREM_DEPTH, env);' },
  FXMOD_PAN_DEPTH:   { sig: '#define FXMOD_PAN_DEPTH 4',    doc: 'fx_mod()/fx_lfo() target: the autopan() depth 0..1.\nfx_mod(0, FXMOD_PAN_DEPTH, 0.8f);' },
  FXMOD_GRAINS_MIX:  { sig: '#define FXMOD_GRAINS_MIX 5',   doc: 'fx_mod()/fx_lfo() target: the grains() dry/wet 0..1 (swell the granular cloud in and out). Call grains() first to allocate the tank.\nfx_lfo(0, FXMOD_GRAINS_MIX, 0.15f, 0.4f, 0.4f);' },
  FXMOD_SHIMMER_MIX: { sig: '#define FXMOD_SHIMMER_MIX 6',  doc: 'fx_mod()/fx_lfo() target: the shimmer() dry/wet 0..1 (bloom the ascending wash in on a swell).\nfx_mod(0, FXMOD_SHIMMER_MIX, env);' },
  ENV_CUTOFF:   { sig: '#define ENV_CUTOFF 0', doc: 'Env target: filter cutoff → the pluck “pew/dwow” sweep. amount in Hz (bipolar; + opens then closes). Needs a filter on the slot.' },
  ENV_PITCH:    { sig: '#define ENV_PITCH 1',  doc: 'Env target: pitch → drum punch / attack snap / zap. amount in semitones (bipolar; + starts sharp and settles to the note).' },
  ENV_DUTY:     { sig: '#define ENV_DUTY 2',   doc: 'Env target: pulse width → a one-shot PWM sweep. Square/pulse slots only. amount 0.0..1.0.' },
  ENV_HARMONICS:{ sig: '#define ENV_HARMONICS 3', doc: 'Env target: the harmonics macro (engine voices). One-shot contour; SNAPPED — steps through the engine’s detents over the attack/decay. amount 0..1.' },
  ENV_TIMBRE:   { sig: '#define ENV_TIMBRE 4', doc: 'Env target: the timbre macro (engine voices) — a per-note brightness contour. amount 0..1.' },
  ENV_MORPH:    { sig: '#define ENV_MORPH 5', doc: 'Env target: the morph macro (engine voices) — e.g. a per-note PD DCW shape layered on the engine’s own. amount 0..1.' },
  ENV_DETUNE:   { sig: '#define ENV_DETUNE 6', doc: 'Env target: the unison spread → THE bloom. A one-shot AD contour opens the wall on the attack — one thin saw blooming into N detuned voices per note. amount in semitones. Needs instrument_unison() on the slot.\ninstrument_env(5, 0, ENV_DETUNE, 0, 400, 0.5f);  // spread blooms over the first 400ms' },
  FILTER_OFF:   { sig: '#define FILTER_OFF 0',   doc: 'No filter (default).' },
  FILTER_LOW:   { sig: '#define FILTER_LOW 1',   doc: 'Lowpass — keeps lows, muffles highs. Warm/round.' },
  FILTER_HIGH:  { sig: '#define FILTER_HIGH 2',  doc: 'Highpass — keeps highs, thins out lows. Tinny/bright.' },
  FILTER_BAND:  { sig: '#define FILTER_BAND 3',  doc: 'Bandpass — keeps only a band around the cutoff. Vowel/wah.' },
  FILTER_NOTCH: { sig: '#define FILTER_NOTCH 4', doc: 'Notch — scoops OUT a band around the cutoff. Phasey/hollow.' },
  FILTER_STEINER:{ sig: '#define FILTER_STEINER 6', doc: 'A Steiner-Parker-style nonlinear 2-pole filter — the Behringer Neutron’s voice. Where FILTER_LOW stays clean and FILTER_LADDER stays creamy, this one is raw and aggressive: a diode-style nonlinearity in the resonance path makes it get dirty and SCREAM as resonance climbs. The gnarly filter; great for acid and biting leads. Multimode — FILTER_STEINER is the lowpass; FILTER_STEINER_HP/BP/NF are the high/band/notch responses.\ninstrument_filter(5, FILTER_STEINER, 600, 13);' },
  FILTER_STEINER_HP:{ sig: '#define FILTER_STEINER_HP 7', doc: 'The Steiner-Parker filter’s HIGHPASS response (aggressive/nonlinear). See FILTER_STEINER.' },
  FILTER_STEINER_BP:{ sig: '#define FILTER_STEINER_BP 8', doc: 'The Steiner-Parker filter’s BANDPASS response (aggressive/nonlinear). See FILTER_STEINER.' },
  FILTER_STEINER_NF:{ sig: '#define FILTER_STEINER_NF 9', doc: 'The Steiner-Parker filter’s NOTCH response (aggressive/nonlinear). See FILTER_STEINER.' },
  FILTER_LADDER:{ sig: '#define FILTER_LADDER 5', doc: 'The Moog 4-pole transistor-ladder lowpass. Steeper (24dB/oct) and creamier than FILTER_LOW, and the feedback drains the bass as resonance climbs — near the top it self-oscillates into a pure tone. The fat, vocal synth filter; pair with instrument_drive for the classic Minimoog bite.\ninstrument_filter(5, FILTER_LADDER, 700, 11);' },
  FILTER_DIODE:{ sig: '#define FILTER_DIODE 10', doc: 'The TB-303 diode-ladder lowpass — THE acid filter. ~18dB/oct (between FILTER_LOW\u2019s 12 and the Moog ladder\u2019s 24), drains the bass as resonance climbs, and the resonance saturates INSIDE the loop (the diodes) so it growls instead of ringing clean — self-oscillates at the top. Pair with ENV_CUTOFF + instrument_drive for the full squelch. Lowpass-only, like the hardware.\ninstrument_filter(5, FILTER_DIODE, 600, 12);' },
  INSTR_SQUARE: { sig: '#define INSTR_SQUARE 0',                                      doc: 'Square wave — chiptune lead.' },
  INSTR_SAW:    { sig: '#define INSTR_SAW 1',                                         doc: 'Sawtooth — bright, buzzy.' },
  INSTR_TRI:    { sig: '#define INSTR_TRI 2',                                         doc: 'Triangle — soft, flute-like.' },
  INSTR_NOISE:  { sig: '#define INSTR_NOISE 3',                                       doc: 'Noise — hihats, explosions.' },
  INSTR_SINE:   { sig: '#define INSTR_SINE 4',                                        doc: 'Sine — pure tone.' },
  INSTR_USER0:  { sig: '#define INSTR_USER0 5',                                       doc: 'Custom DRAWN waveform 0 — a 64-sample single cycle you fill with wave_set(), then play like any wave: note(60, INSTR_USER0, 5). Draw one in the “wave editor” cart. Defaults to a sine until set.' },
  INSTR_USER1:  { sig: '#define INSTR_USER1 6',                                       doc: 'Custom drawn waveform 1 — see INSTR_USER0 / wave_set().' },
  INSTR_USER2:  { sig: '#define INSTR_USER2 7',                                       doc: 'Custom drawn waveform 2 — see INSTR_USER0 / wave_set().' },
  INSTR_USER3:  { sig: '#define INSTR_USER3 8',                                       doc: 'Custom drawn waveform 3 — see INSTR_USER0 / wave_set().' },
  INSTR_PLUCK:  { sig: '#define INSTR_PLUCK 16',                                      doc: 'Karplus-Strong plucked string — the first modeled ENGINE (wave ids 16+): each note runs a tiny string simulation instead of reading a wavetable, so it decays and darkens like a real string. One id covers guitar / harp / koto — shape it with the three engine macros (instrument_harmonics = ring, instrument_timbre = pick, instrument_morph = position).\nThe string sets its own decay: give it a long hit() duration (or release) so it can ring out. The whole pitch system bends it live — LFO_PITCH vibrato/chorus warble, ENV_PITCH blips, note_pitch/note_glide. Try the “pluck” cart.\ninstrument(5, INSTR_PLUCK, 1, 0, 7, 80);  hit(57, 5, 6, 1500);' },
  INSTR_MALLET: { sig: '#define INSTR_MALLET 17',                                     doc: 'Struck bar — the second modeled ENGINE: four decaying sine modes (the bar’s vibration modes) + a strike click. One id covers marimba / celesta / vibraphone / glockenspiel — shape it with the three engine macros: instrument_harmonics = bar material (0 wood, 1 metal/bell — sweeps the partials), instrument_timbre = mallet hardness (0 soft yarn, 1 hard brass + click), instrument_morph = ring length (0 dry tick, 1 vibraphone sustain — the top switches the motor tremolo on).\nLike PLUCK it decays on its own: give it a long hit() duration (or release) so the ring is never chopped. The whole pitch system bends it live. Try the “mallet” cart.\ninstrument(5, INSTR_MALLET, 1, 0, 7, 1200);  hit(69, 5, 6, 2000);' },
  INSTR_FM:     { sig: '#define INSTR_FM 18',                                         doc: 'Two-operator FM — the third modeled ENGINE: an inaudible modulator sine bends the carrier’s phase, the DX-synth recipe. One id covers electric piano / glass bells / solid bass / brassy growl / clang — shape it with the three engine macros: instrument_harmonics = carrier:modulator ratio (SNAPPED detents — integer ratios sound harmonic/musical, off-integer = bells, the top is the DX “tine”), instrument_timbre = brightness (FM amount — it decays within each note like a real DX strike, bright attack to mellow tail), instrument_morph = modulator feedback (0 clean, up = saw-edge growl, top = noisy clang).\nThe 1:1 ratio detent carries a built-in DX “tine” — the E.PIANO attack ping (scales with timbre, fades with feedback). Unlike PLUCK/MALLET the engine doesn’t decay on its own — give it a normal ADSR. Try the “fm” cart.\ninstrument(5, INSTR_FM, 2, 600, 3, 300);  note(57, 5, 6);' },
  INSTR_ORGAN:  { sig: '#define INSTR_ORGAN 19',                                      doc: 'Tonewheel organ — the fourth modeled ENGINE: nine additive drawbar sines at the Hammond footages, so each note is a registration (a recipe of harmonics), not a single wave. Unlike PLUCK/MALLET it is HELD — it holds while the note sounds (use note_on/note_off, or a long hit()), so the macros morph the tone LIVE. Shape it with the three engine macros: instrument_harmonics = registration (SNAPPED drawbar recipes — thin combo to full gospel), instrument_timbre = brightness tilt + key click, instrument_morph = animation (0 = still combo organ, up = scanner chorus shimmer + percussion).\nThe Leslie is NOT built in — it is a per-voice recipe (LFO_VOLUME + LFO_PITCH with the rate lerped slow↔fast). Try the “organ” cart.\ninstrument(5, INSTR_ORGAN, 1, 0, 7, 200);  note_on(48, 5, 6);' },
  INSTR_EPIANO: { sig: '#define INSTR_EPIANO 20',                                    doc: 'Electric piano — the fifth modeled ENGINE: Rhodes / Wurlitzer / Clavinet in one. 12 decaying inharmonic sine modes pushed through a pickup nonlinearity (the bark/buzz/honk that makes it electric, not a dull bell), buffer-free. Struck and self-decaying like PLUCK/MALLET — give it a long hit() (or release) so the ring isn’t chopped. Shape it with the three engine macros: instrument_harmonics = instrument (SNAPPED — Rhodes / Wurli / Clav, each its own ratio table + pickup character), instrument_timbre = brightness (pickup position + hammer hardness, mellow → bright/snappy), instrument_morph = bark (the pickup drive — clean fundamental → growl when you dig in).\nThe DX/digital electric piano is INSTR_FM; this is the electromechanical one. Try the “epiano” cart.\ninstrument(5, INSTR_EPIANO, 1, 0, 7, 1200);  hit(60, 5, 6, 2000);' },
  INSTR_PD: { sig: '#define INSTR_PD 21',                                              doc: 'Phase distortion — the sixth modeled ENGINE: the Casio CZ sound. Buzzy basses, bright resonant leads, synth-brass, and the famous CZ “wowww” sweep — all from warping the phase a cosine reads through (filter-like brightness with no filter). Holds while sustained. Shape it with the three engine macros: instrument_harmonics = wavetype (SNAPPED across 8 — saw / square / pulse / doublepulse / sawpulse, then 3 resonant types), instrument_timbre = distortion amount (brightness / how high the resonant peak sits), instrument_morph = the DCW envelope (0 = static; turn it up and the distortion snaps bright on the strike then settles — the CZ envelope sweep). Try the “pd” cart.\ninstrument(5, INSTR_PD, 1, 0, 7, 1200);  note(48, 5, 6);' },
  INSTR_MEMBRANE: { sig: '#define INSTR_MEMBRANE 22',                                  doc: 'Membrane drum — the seventh modeled ENGINE: a struck drumhead. Six decaying sine modes at a circular membrane’s vibration ratios + a slap contact click, buffer-free. One id covers tabla / conga / bongo / djembe / tom — hand percussion the analog 808/909 recipes structurally can’t reach (real modes + a pitch bend, not one sine + a pitch env). Struck and self-decaying like MALLET — give it a long hit() (or release) so the ring isn’t chopped. Shape it with the three engine macros: instrument_harmonics = head character (0 = tuned harmonic tabla, pitched + longer ring → 1 = inharmonic djembe/conga thud), instrument_timbre = strike position (0 = center thump → 1 = edge ring + slap click — open/slap/mute in one knob), instrument_morph = pitch bend (0 = flat; up = the tabla bayan glissando — pitch swoops off the strike and settles). Try the “tabla” cart.\ninstrument(5, INSTR_MEMBRANE, 1, 0, 7, 1200);  hit(50, 5, 6, 600);' },
  INSTR_REED: { sig: '#define INSTR_REED 23',                                          doc: 'Reed — the eighth modeled ENGINE: a blown single/double-reed instrument. A self-oscillating bore waveguide (a delay line + a pressure-driven reed valve), so unlike the struck engines it HOLDS for as long as the note sustains — like ORGAN. One id covers clarinet / soprano-alto-tenor sax / oboe — the blown family the wavetables can’t reach. Shape it with the three engine macros: instrument_harmonics = bore shape (0 = cylindrical clarinet, hollow + odd-harmonics-only → 1 = conical sax, full + bright), instrument_timbre = reed edge (0 = soft + dark → 1 = stiff + nasal/bright), instrument_morph = breath (0 = soft steady tone → 1 = a leaning, growling breath with deeper vibrato). Because it holds, the macros work as live expression — sweep instrument_morph while a note rings for a breath swell. Try the “reed” cart.\ninstrument(5, INSTR_REED, 1, 0, 4, 1200);  note_on(60, 5, 6);' },
  INSTR_PIPE: { sig: '#define INSTR_PIPE 25',                                          doc: 'Pipe — the ninth modeled ENGINE: a blown flute. An STK jet-drive bore (a delay line + an air jet that strikes the labium edge and self-oscillates), so like REED and ORGAN it HOLDS for as long as the note sustains. One id covers concert flute / recorder / pan pipe — breathy, airy, woody. Shape it with the three engine macros: instrument_harmonics = overblow (0 = pure fundamental → 1 = the octave flageolet jump + bright harmonics), instrument_timbre = breath air (0 = pure tone → 1 = airy/breathy — a flute is mostly air), instrument_morph = embouchure (0 = hollow/dark, the recorder → 1 = focused/bright, the concert flute). Because it holds, the macros are live expression — sweep instrument_harmonics on a sustained note to overblow to the octave. ⚠ TUNING: a waveguide flute’s intonation tracks the embouchure (morph) — it’s in tune for a FOCUSED embouchure (morph ≳ 0.5, e.g. the showcase flute m0.70, in tune C4→~E6) but drifts flat/unstable at the top with a hollow/low embouchure (morph ≲ 0.4) or overblow. Keep a melodic flute in a natural register and verify a new voice: node tools/tune-check.js --engine PIPE --macros h,t,m --range lo-hi. Try the “pipe” cart.\ninstrument(5, INSTR_PIPE, 1, 0, 4, 1200);  note_on(72, 5, 6);' },
  INSTR_GUITAR: { sig: '#define INSTR_GUITAR 26',                                        doc: 'Guitar — a bodied plucked string. A Karplus-Strong string fed through a resonant body (4 parallel formant bandpasses), which is what gives it the box that bare INSTR_PLUCK lacks. Struck/plucked — it rings down on its own, so give it a long hit() or release. One id covers acoustic / nylon / banjo / koto / harp / ukulele — and pizzicato. Shape it with the three engine macros: instrument_harmonics = body (0 = open & bodyless, the harp → 1 = resonant bright box, the banjo), instrument_timbre = string brightness (0 = warm nylon → 1 = bright steel), instrument_morph = mute (0 = long open ring → 1 = tight muted pizzicato stop). Try the “guitar” cart.\ninstrument(5, INSTR_GUITAR, 1, 0, 4, 1200);  note(60, 5, 6);' },
  INSTR_PIANO: { sig: '#define INSTR_PIANO 27',                                         doc: 'Piano — a struck stiff string (StifKarp). A Karplus-Strong string plus a DISPERSION allpass chain that stretches the upper partials sharp — the inharmonic, slightly metallic shimmer your ear reads as "piano" (and as dulcimer/clavichord) rather than a plain string — run through a grand-piano soundboard. Struck, it rings down on its own, so give it a long hit(). One id covers grand / bright piano / harpsichord / dulcimer / clavichord / celesta. Shape it with the three engine macros: instrument_harmonics = voicing (snaps across the six instruments — grand → bright → harpsichord → dulcimer → clavichord → celesta), instrument_timbre = hammer (0 = soft felt, mellow → 1 = hard, bright plectrum strike), instrument_morph = pedal (0 = dry/damped staccato → 1 = long open sustain, like holding the sustain pedal). Try the “piano” cart.\ninstrument(5, INSTR_PIANO, 1, 0, 4, 2000);  note(60, 5, 6);' },
  INSTR_BOWED: { sig: '#define INSTR_BOWED 28',                                         doc: 'Bowed string — violin / cello / viola. A Smith/McIntyre stick-slip friction waveguide: a bow drags across the string, the rosin grips and releases, and that drives a self-oscillating loop — so unlike the plucked/struck strings it HOLDS for as long as you sustain the note (give it a long note_on()/release, like INSTR_REED or INSTR_PIPE). It speaks with an attack scratch and grows on a swell. Shape it with the three engine macros: instrument_harmonics = bow position (0 = sul ponticello, near the bridge & bright/edgy → 1 = sul tasto, over the fingerboard & soft), instrument_timbre = bow pressure (0 = light & clean, a singing leaning-sawtooth → 1 = heavy & scratchy "surface sound" — a real, playable articulation, not a bug), instrument_morph = bow speed / swell (0 = gentle → 1 = digging in, louder and cleaner). PIZZICATO is the same string plucked: set instrument_mode(slot, MODE_BOW_PIZZ, 1) and the engine seeds the waveguide with a pluck and switches the bow friction off, so the very same string and body ring down (give it a long hit() — it decays on its own). Try the “bowed” cart.\ninstrument(5, INSTR_BOWED, 120, 0, 7, 400);  int h = note_on(57, 5, 6);' },
  INSTR_BRASS: { sig: '#define INSTR_BRASS 29',                                         doc: 'Brass — the lip-reed family: trumpet / cornet / flugelhorn / trombone / french horn / tuba. An STK BrassInstrument waveguide: a bore delay line closed by a flaring bell, driven by a LIP VALVE modeled as a resonant biquad (the buzzing lips). It self-oscillates, so like INSTR_REED / INSTR_PIPE it HOLDS for as long as the note sustains (give it a long note_on()/release). Its signature is BRASSINESS — blow harder and the tone steepens into a bright, blatty shockwave, the way a real horn opens up at fortissimo. Shape it with the three engine macros: instrument_harmonics = instrument / bore (0 = tight bright trumpet → cornet → flugelhorn → trombone → french horn → 1 = dark wide tuba), instrument_timbre = brassiness (0 = round & mellow → 1 = loud & blatty, the overtone explosion), instrument_morph = breath / lip lean-in (0 = soft steady tone → 1 = a growling breath with deeper vibrato). Because it holds and tracks pitch live, it SLURS and GLISSES — drive note_pitch / note_glide for the trombone slide. Try the “brass” cart.\ninstrument(5, INSTR_BRASS, 1, 0, 4, 1200);  int h = note_on(53, 5, 6);' },
  INSTR_SAMPLE: { sig: '#define INSTR_SAMPLE 30',                                       doc: 'PCM sample playback — the one engine that plays a RECORDED buffer instead of synthesizing. Pair it with the sampler API: record_arm() starts capturing the console’s own output, record_grab(slot, seconds) freezes the recent audio into a PCM slot, then instrument_sample(instr_slot, sample_slot, root_midi) binds it. Play the instrument slot from a keybed and your recording plays back chromatically — root_midi at original speed, higher notes faster/up. One-shot forward playback for now (loop / reverse / slice to come). The fantasy-console sampler: you play with the sound the machine just made. See mic-and-sampling.md.\ninstrument(5, INSTR_SAMPLE, 1, 0, 7, 200);\nrecord_grab(0, 2.0f);  instrument_sample(5, 0, 60);' },
  INSTR_VOICE: { sig: '#define INSTR_VOICE 24',                                         doc: 'Voice — a formant singing/speaking engine (navkit VoicForm port): a glottal pulse through 4 vowel formants. HOLDS while sustained. The three macros are the voice: instrument_harmonics = VOWEL (U→O→A→E→I), instrument_timbre = SIZE (vocal-tract length — giant→child), instrument_morph = EFFORT (soft/dark/relaxed → bright/pressed). voice_nasal() adds the 4th axis, the nasal/hummed color (the chant). voice_consonant()/voice_coda() articulate syllables ("bah", "ah-m") over the full 10-vowel/22-consonant set — re-fire mid-note for connected speech. Vibrato is note_lfo(LFO_PITCH). Try the vox / voxpad carts.\ninstrument(5, INSTR_VOICE, 45, 60, 7, 160);  int h = note_on(48, 5, 6);  voice_nasal(h, 0.6f);' },
  wave_set:     { sig: 'void wave_set(int which, const float *samples, int n)',       doc: 'Fill custom wave INSTR_USER0+which (which 0–3) with one cycle of a waveform: n samples in -1..1, resampled to the 64-entry table. It’s LIVE — a ringing note morphs as you redraw. Draw waves by hand in the “wave editor” cart and press E to export this call.\nfloat w[64]; /* fill */ wave_set(0, w, 64); note(60, INSTR_USER0, 5);' },
  tone:           { sig: 'void tone(int scale, int octave, int instr, int vol)',       doc: 'Play a random note from a musical scale.\noctave 3–6 typical (4 = middle C).' },
  SCALE_MAJOR:    { sig: '#define SCALE_MAJOR 0',                                      doc: 'Major scale — happy, do re mi.' },
  SCALE_MINOR:    { sig: '#define SCALE_MINOR 1',                                      doc: 'Natural minor — sad / mysterious.' },
  SCALE_PENTA:    { sig: '#define SCALE_PENTA 2',                                      doc: 'Major pentatonic (5 notes) — always sounds nice, hard to play a wrong note.' },
  SCALE_PENTA_MIN:{ sig: '#define SCALE_PENTA_MIN 3',                                  doc: 'Minor pentatonic — bluesy, moody.' },
  SCALE_BLUES:    { sig: '#define SCALE_BLUES 4',                                      doc: 'Blues scale — minor penta + flat 5.' },
  SCALE_CHROMATIC:{ sig: '#define SCALE_CHROMATIC 5',                                  doc: 'All 12 semitones — atonal, dissonant.' },
  chord:          { sig: 'void chord(int root, int type, int instr, int vol)',         doc: 'Play a chord stacked on a MIDI root note.\nroot: MIDI note (60 = middle C). type: CHORD_*.' },
  strum:          { sig: 'void strum(int root, int type, int instr, int vol, int delay_ms)', doc: 'Like chord(), but notes are spread across delay_ms apart (~20–80ms feels guitar-like).\nNegative delay_ms strums from high to low (down-strum).' },
  strum_notes:    { sig: 'void strum_notes(const int *midis, int n, int instr, int vol, int delay_ms)', doc: 'Strum an explicit list of MIDI notes (not a chord type) — for voicings you build yourself.\ndelay_ms spreads the notes (0 = block, ~20–80ms = harp roll); negative = down-strum.\nint v[3] = {60,64,67}; strum_notes(v, 3, INSTR_PLUCK, 5, 30);' },
  schedule:       { sig: 'void schedule(int delay_ms, int midi, int instr, int vol)',  doc: 'Play a note delay_ms in the future. Non-blocking — queues into the audio thread.' },
  schedule_hit:   { sig: 'void schedule_hit(int delay_ms, int midi, int instr, int vol, int dur_ms)', doc: 'schedule() + hit() in one: a custom-length note at a sample-accurate future time. THE tool for fast sfx/arp steps — queue each step a few ms ahead and the audio thread fires them with zero frame-rate jitter (steps shorter than a frame stay crisp).\nschedule_hit(i * 8, 60 + i, INSTR_SQUARE, 6, 12);  // an 8ms-step zap' },
  bpm:            { sig: 'void bpm(int rate)',                                         doc: 'Set tempo in beats per minute (default 120).' },
  beat:           { sig: 'int beat()',                                                 doc: 'Current beat counter — advances each beat based on bpm().' },
  every:          { sig: 'bool every(int n)',                                          doc: 'True once per n beats, on the beat. Use in update() to fire something rhythmically:\nif (every(4)) chord(60, CHORD_MAJ7, INSTR_TRI, 5);' },
  beat_pos:       { sig: 'float beat_pos()',                                           doc: 'Fractional position within the current beat: 0.0 just after a beat hits, approaching 1.0 just before the next one. Useful for fades, pulses, and continuous modulation.' },
  euclid:         { sig: 'bool euclid(int hits, int steps, int b)',                    doc: 'Bjorklund/Euclidean rhythm — true when step b is one of `hits` spread as evenly as possible across `steps`. Not just for music: it distributes ANY repeating event evenly. Pass any counter as b — beat(), frame()/10, a wave index — to spawn enemies, place pickups, or stagger blinks on a regular-but-not-boring cadence.\neuclid(3, 8, beat()) → tresillo beat  •  euclid(2, 7, frame()/30) → an event on 2 of every 7 ticks.' },
  chance:         { sig: 'bool chance(int percent)',                                   doc: 'True with the given probability percent (0–100) — a weighted coin flip. Used all over, not just music: random item drops, enemy variety, branching events, occasional glitches, "did it hit?" rolls.\nif (chance(30)) drop_powerup();   •   if (every(1) && chance(40)) note(60, INSTR_SAW, 4);' },
  degree:         { sig: 'int degree(int scale, int octave, int n)',                   doc: 'MIDI note for the nth degree of a scale, rooted at C. Wraps octaves for n outside the scale length, so degree(SCALE_PENTA, 4, 7) is one octave up from degree 2.' },
  CHORD_MAJ:      { sig: '#define CHORD_MAJ 0',                                        doc: 'Major triad — bright, resolved.' },
  CHORD_MIN:      { sig: '#define CHORD_MIN 1',                                        doc: 'Minor triad — sad, soft.' },
  CHORD_DIM:      { sig: '#define CHORD_DIM 2',                                        doc: 'Diminished — tense, unresolved.' },
  CHORD_AUG:      { sig: '#define CHORD_AUG 3',                                        doc: 'Augmented — uneasy, dreamlike.' },
  CHORD_MAJ7:     { sig: '#define CHORD_MAJ7 4',                                       doc: 'Major 7th — jazzy, sophisticated.' },
  CHORD_MIN7:     { sig: '#define CHORD_MIN7 5',                                       doc: 'Minor 7th — smooth, soulful.' },
  CHORD_DOM7:     { sig: '#define CHORD_DOM7 6',                                       doc: 'Dominant 7th — bluesy, wants to resolve.' },
  CHORD_SUS4:     { sig: '#define CHORD_SUS4 7',                                       doc: 'Suspended 4th — open, suspended.' },
  CHORD_POWER:    { sig: '#define CHORD_POWER 8',                                      doc: 'Power chord — root + fifth, no third. Rock staple.' },
  rnd:                { sig: 'int rnd(int n)',                                              doc: 'Random integer in [0, n). rnd(6) returns 0–5.' },
  rnd_between:        { sig: 'int rnd_between(int lo, int hi)',                           doc: 'Random integer in [lo, hi). rnd_between(3, 8) returns 3–7.' },
  rnd_float:          { sig: 'float rnd_float()',                                         doc: 'Random float 0..1.' },
  rnd_float_between:  { sig: 'float rnd_float_between(float lo, float hi)',               doc: 'Random float in [lo, hi).' },
  now:                { sig: 'float now()',                                                doc: 'Seconds since startup. Use for animations and oscillators.' },
  epoch:              { sig: 'int epoch()',                                                doc: 'Real-world clock: Unix time in whole seconds. Unlike now(), it keeps counting while the cart is closed.\nSave it with save(), then on the next run compare to tell how long the player was away:\nint away = epoch() - load(0);  // seconds since last visit' },
  frame:              { sig: 'int frame()',                                                doc: 'Frame count since startup. Increments once per update().\nif (frame() % 30 == 0) fires twice per second at 60fps.' },
  fps:                { sig: 'int fps()',                                                  doc: 'Measured frames per second right now, smoothed over the last second. 60 means the cart is running smoothly; a lower number means it is too slow. Show it while tuning performance:\nwatch("fps", "%d", fps());' },
  sgn:            { sig: 'int sgn(int n)',                                             doc: 'Sign of n: -1 if negative, 0 if zero, 1 if positive.' },
  mid:            { sig: 'int mid(int a, int b, int c)',                               doc: 'Middle value of three. Common use is clamp: mid(lo, value, hi).' },

  printh:         { sig: 'void printh(const char *fmt, ...)',                          doc: 'printf-style logging to the editor\'s runtime log panel (not the game window).\nAnswers "what is this value?" and "did this run?".\nExample: printh("score %d", score);' },
  watch:          { sig: 'void watch(const char *name, const char *fmt, ...)',         doc: 'Show a named, live value in the corner of the game window. printf-style, so it works for any type.\nExample: watch("x", "%d", x);  watch("pos", "(%d, %d)", x, y);\nA value fades out about a second after you stop calling watch() for it. Press F1 to hide/show.' },
  watch_visible:  { sig: 'void watch_visible(bool on)',                                doc: 'Show or hide the watch() overlay (default: on). Handy for clean screenshots. F1 toggles it too.' },
  paused:         { sig: 'bool paused(void)',                                          doc: 'True while the runtime pause overlay is open (P/ENTER to toggle). A key the cart reads via key()/keyp()/keyr() is claimed by the cart and never triggers pause - a cart using the whole keyboard keeps P.\nif (paused()) return;' },
  palette_hex:    { sig: 'void palette_hex(int i, int hex)',                            doc: 'EXPERIMENTAL — for palette TESTING only, not for games; may change or vanish. Writes a raw 0xRRGGBB into live palette slot i (0-63): primitives, text AND existing sprite art recolor immediately (it rides the pal() shader). pal_reset() restores the shipped palette. Caveat: pal(c0,c1) under a custom palette injects the SHIPPED c1 color. The palette lab cart is the intended user — see docs/design/palette-and-color.md.\npalette_hex(8, 0xe83b3b);  // try a different red' },

  timer:          { sig: 'float timer()',                                              doc: 'Seconds since the last timer_reset() (or startup). A resettable stopwatch.\nUse for round timers, "how long did you survive?", cooldowns.' },
  timer_reset:    { sig: 'void timer_reset()',                                          doc: 'Reset timer() back to 0.' },
  save:       { sig: 'void save(int slot, int value)', doc: 'Store an integer that survives between runs. 64 slots (0–63) per cart — each cart keeps its own save files (build/saves/<cart>/).\nTypical use: save(0, high_score);' },
  load:       { sig: 'int load(int slot)',              doc: 'Read back a saved value. Returns 0 if the slot was never written.\nTypical use: int hi = load(0);' },
  save_int:   { sig: 'void save_int(const char *key, int value)', doc: 'Store an integer by name instead of a slot number — no numbering to remember. Up to 64 keys per cart.\nsave_int("hiscore", score);' },
  load_int:   { sig: 'int load_int(const char *key, int def)', doc: 'Read a named value back. Returns `def` if that key was never saved.\nint hi = load_int("hiscore", 0);' },
  de_state:   { sig: 'void *de_state(int bytes)', doc: 'A zero-filled block of `bytes` bytes that the engine owns — put your whole cart state in it. Unlike a normal global it survives a live code-reload, so the game keeps running across an edit. The starter cart wraps it so you just write:\nSTATE { int x, y, score; };\n// then S->x, S->score — and they survive a reload' },
  STATE:      { sig: '#define STATE struct GameState', doc: 'Declare your cart\'s state. Write it once near the top with the fields you need:\nSTATE { int x; int score; };\nThe block is engine-owned, so it SURVIVES a live code-reload — edit and re-run and your values are kept (a plain global would reset). Read & write it through `S` (e.g. S->score). Friendly sugar over `de_state()`; lives in the starter cart, not studio.h.' },
  S:          { sig: '#define S ((STATE *)de_state(sizeof(STATE)))', doc: 'Your cart\'s state — a pointer to the `STATE { ... }` block you declared. Use S->field to read or write it; the values survive a live reload, so you can tweak code while the game runs without losing where you were.\nS->score += 10;\nGotcha: if you reorder/retype fields in STATE, relaunch (close + run) so the block is freshly zeroed. Sugar over `de_state()`.' },
  GameState:  { sig: 'struct GameState  // your STATE block', doc: 'The struct type behind `STATE { ... }` and `S`. You normally never write `GameState` directly — you declare it as STATE { ... } and use it through S->field. See STATE, S and de_state.\nSTATE { int x; int score; };' },

  // ── external data ── (a cart that loads a world from a file — decision 0025)
  de_data_path:    { sig: 'const char *de_data_path(void)', doc: 'The path handed to the cart at launch with --data <file> (or the $DE_DATA env var), else NULL. A data-driven cart reads its world from it at startup — sloop and roadview load real OpenStreetMap cities this way (swap the file, drive a different city).\nconst char *p = de_data_path();\nif (p) load_world(p);' },
  de_dropped_file: { sig: 'const char *de_dropped_file(void)', doc: 'The path of a file dragged onto the game window THIS frame, else NULL. Poll it in update() to let the player swap data at runtime — drop a new city file on sloop and you drive that city.\nconst char *drop = de_dropped_file();\nif (drop) load_world(drop);' },
  de_open_path:    { sig: 'void de_open_path(const char *path)', doc: 'Reveal a file or folder in the OS file manager (Finder / Explorer) — show the player where the cart\'s data files live so they can find or drop in new ones.\nif (keyp(\'O\')) de_open_path("../data");' },
  de_switch_cart:  { sig: 'void de_switch_cart(int ctx)', doc: 'Multi-cart bundles: switch to sound context `ctx` (0–7). Each context keeps a whole separate sound world — instruments, effects, wave tables, bpm — recorded as the cart configures it and restored when you switch back. Same ctx = no-op; a never-used ctx starts at clean boot defaults. Hanging notes are faded, scheduled notes cleared. Single carts never need this — it\'s the seam a bundle\'s dispatcher shim calls when changing racks (see docs/design/share-panel.md).\nif (keyp(KEY_TAB)) de_switch_cart(1);' },

  // ── math ── (angles in degrees: 0 = right, 90 = down)
  abs:        { sig: 'int abs(int v)',                                                 doc: 'Absolute value — drops the minus sign. abs(-5) is 5.' },
  min:        { sig: 'int min(int a, int b)',                                          doc: 'The smaller of two numbers.' },
  max:        { sig: 'int max(int a, int b)',                                          doc: 'The bigger of two numbers.' },
  clamp:      { sig: 'float clamp(float v, float lo, float hi)',                       doc: 'Keep v between lo and hi. Below lo gives lo, above hi gives hi.\nFloat-friendly version of mid(lo, v, hi).' },
  blink:          { sig: 'bool blink(int period)',         doc: 'Flashing helper driven by frame(): true for `period` frames, then false for `period` frames, repeating.\nblink(3) is a fast flash; blink(15) a slow one. Use it to flash an invincible player:\nif (invincible && blink(3)) spr(0, x, y);  // skip the draw on the off frames' },
  ease_in:        { sig: 'float ease_in(float t)',       doc: 'Start slow, end fast. t must be 0..1. Compose with lerp:\nfloat x = lerp(startX, endX, ease_in(t));' },
  ease_out:       { sig: 'float ease_out(float t)',      doc: 'Start fast, end slow. t must be 0..1.' },
  ease_in_out:    { sig: 'float ease_in_out(float t)',   doc: 'Slow → fast → slow. The most natural-feeling easing. t must be 0..1.' },
  ease_back:      { sig: 'float ease_back(float t)',      doc: 'Overshoot past the end, then settle back — a snappy "pop". Returns slightly >1 near the end, pushing a value past its target before it springs home. t must be 0..1.\nint x = lerp(startX, endX, ease_back(t));' },
  lerp:       { sig: 'float lerp(float a, float b, float t)',                          doc: 'Mix between a and b. t=0 gives a, t=1 gives b, t=0.5 the middle.\nGreat for smooth camera follow, fades, color blends.' },
  remap:      { sig: 'float remap(float v, float a, float b, float c, float d)',       doc: 'Remap v from the range a..b into the range c..d.\nremap(health, 0, 100, 0, SCREEN_W) turns health into a bar width.' },
  distance:   { sig: 'float distance(int x1, int y1, int x2, int y2)',                 doc: 'Distance between two points, in pixels.' },
  length:     { sig: 'float length(int x, int y)',                                     doc: 'Length of the vector (x, y) — its distance from the origin.' },
  fsqrt:      { sig: 'float fsqrt(float v)',                                           doc: 'Square root of v. Returns 0 for v <= 0, so it never errors.\nHandy for vector magnitudes without including math.h: float d = fsqrt(dx*dx + dy*dy);' },
  angle_to:   { sig: 'float angle_to(int x1, int y1, int x2, int y2)',                 doc: 'Direction in degrees from point 1 to point 2.\n0 = right, 90 = down, 180 = left, -90 = up. Pairs with dx()/dy().' },
  dx:         { sig: 'float dx(float steps, float degrees)',                           doc: 'How far to move in x when stepping `steps` pixels at this angle.\nKeep position in a float so sub-pixel motion adds up: x += dx(2, dir);' },
  dy:         { sig: 'float dy(float steps, float degrees)',                           doc: 'How far to move in y when stepping `steps` pixels at this angle.\nPairs with dx() — y grows downward. Keep position in a float.' },
  sin_deg:    { sig: 'float sin_deg(float degrees)',                                   doc: 'Sine of an angle in degrees (-1.0 to 1.0).' },
  cos_deg:    { sig: 'float cos_deg(float degrees)',                                   doc: 'Cosine of an angle in degrees (-1.0 to 1.0).' },

  // ── collision ──
  boxes_touch:     { sig: 'bool boxes_touch(int ax, int ay, int aw, int ah, int bx, int by, int bw, int bh)', doc: 'True if two rectangles overlap. The everyday sprite collision check (AABB).' },
  point_in_box:    { sig: 'bool point_in_box(int px, int py, int bx, int by, int bw, int bh)', doc: 'True if the point (px, py) is inside the rectangle.' },
  circles_touch:   { sig: 'bool circles_touch(int ax, int ay, int ar, int bx, int by, int br)', doc: 'True if two circles overlap (centres + radii).' },
  near:            { sig: 'bool near(int ax, int ay, int bx, int by, int d)',          doc: 'True if the two points are within d pixels of each other.' },
  touching_map:    { sig: 'bool touching_map(int x, int y, int w, int h)',             doc: 'True if this pixel-space box overlaps any non-empty map cell (value != 0).\nThe easy "am I standing on a wall?" check.' },
  tile_at:         { sig: 'int tile_at(int px, int py)',                               doc: 'Tile index of the map cell under pixel (px, py). 0 if empty/out of bounds.\nConverts pixels → cell using the current cell size and map_scale().' },
  touching_color:  { sig: 'bool touching_color(int x, int y, int w, int h, int color)', doc: 'True if any pixel inside this box is the given palette color.\nPaint your walls one color, then ask "am I touching it?" — collision with no hitboxes.' },

  // ── animation ──
  anim:       { sig: 'int anim(int n_frames, float fps, float phase)',                 doc: 'Which animation frame to show right now (0..n_frames-1), looping forever.\nphase 0..1 offsets the cycle start — use (float)i/count to stagger multiple entities.\nspr(walk + anim(4, 10, 0), x, y); — a 4-frame walk cycle at 10 fps.\nspr(walk + anim(4, 10, (float)i/5), x, y); — 5 entities walking out of phase.' },

  // ── strings ──
  str:        { sig: 'const char *str(const char *fmt, ...)',                          doc: 'Build a string with values in it, printf-style, for print().\nprint(str("score %d", score), 4, 4, CLR_WHITE);\nReuses a few buffers — fine within a frame, don\'t store the result.' },
  noise:      { sig: 'float noise(float x)',                   doc: 'Smooth random value 0..1. Nearby x values give similar results — great for wobble, pulses, organic motion.\nnoise(now()) drifts slowly over time.' },
  noise2:     { sig: 'float noise2(float x, float y)',         doc: 'Smooth 2D random value 0..1. Use for terrain height, fog density, flow fields.\nScale your inputs: noise2(x*0.05, y*0.05) for gentle hills.' },
  noise3:     { sig: 'float noise3(float x, float y, float z)', doc: 'Smooth 3D random value 0..1. Animates 2D noise by passing now() as z.\nnoise3(x*0.05, y*0.05, now()*0.5) gives slowly drifting terrain.' },

  // ── 3D helpers ──
  V3:         { sig: 'typedef struct { float x, y, z; } V3', doc: 'A 3D point/vector — three floats. Build a model from a list of these, then rot3/project them.\nV3 p = { 1, -1, 2 };' },
  rot3:       { sig: 'V3 rot3(V3 p, float yaw, float pitch)', doc: 'Rotate a point: yaw (around the Y axis) then pitch (around the X axis), both in degrees. The everyday spin-a-model call.\nV3 r = rot3(vert[i], angle, 20);' },
  project3:   { sig: 'bool project3(V3 p, float focal, float zoom, int *sx, int *sy)', doc: 'Perspective-divide a rotated point to screen pixels (origin = screen centre). Bigger focal = flatter; zoom scales it up. Returns false if the point is behind the camera.\nint x, y; if (project3(r, 4, 48, &x, &y)) circfill(x, y, 2, 7);' },
  zsort:      { sig: 'void zsort(float *key, int *order, int n)', doc: 'Painter\'s sort: fills order[] with indices 0..n-1 ordered far→near by key[]. No z-buffer needed — draw your faces/sprites via order[i].\nfloat z[N]; int o[N]; zsort(z, o, n); for (i) draw(face[o[i]]);' },
  quadfill:   { sig: 'void quadfill(int x0, int y0, int x1, int y1, int x2, int y2, int x3, int y3, int color)', doc: 'Fill a four-cornered polygon (two triangles sharing the 0–2 diagonal). Corners go in order around the face. The solid-3D / road-segment workhorse.\nquadfill(x0,y0, x1,y1, x2,y2, x3,y3, CLR_BLUE);' },
  ngon:       { sig: 'void ngon(int x, int y, int r, int sides, float rot, int color)',         doc: 'Regular n-sided polygon outline. rot=0 puts the first point to the right (degrees). ngon(x,y,r,6,0,c) = hexagon, ngon(...,3,...) = triangle.\nngon(80, 60, 20, 6, 0, CLR_WHITE);' },
  ngonfill:   { sig: 'void ngonfill(int x, int y, int r, int sides, float rot, int color)',     doc: 'Filled regular polygon — triangle fan from the center. Respects fillp(). ngonfill(x,y,r,6,0,c) = solid hexagon.\nngonfill(80, 60, 20, 6, 30, CLR_GREEN);' },
  star:       { sig: 'void star(int x, int y, int r_out, int r_in, int points, float rot, int color)',     doc: 'Star outline. r_out = tip radius, r_in = inner radius, points = number of tips. rot in degrees.\nstar(80, 60, 20, 8, 5, 0, CLR_YELLOW);' },
  starfill:   { sig: 'void starfill(int x, int y, int r_out, int r_in, int points, float rot, int color)', doc: 'Filled star. Respects fillp(). Great for sparkles, badges, pickups.\nstarfill(80, 60, 20, 8, 5, 0, CLR_YELLOW);' },
  poly:       { sig: 'void poly(int *xy, int n, int color)',     doc: 'Polygon outline through n points, auto-closed. xy is a flat array of pairs: {x0,y0, x1,y1, ...}.\nint pts[] = {10,10, 50,5, 60,40, 20,45}; poly(pts, 4, CLR_WHITE);' },
  polyfill:   { sig: 'void polyfill(int *xy, int n, int color)', doc: 'Filled polygon through n points (even-odd coverage — handles concave shapes too). Respects fillp().\nint pts[] = {10,10, 50,5, 60,40, 20,45}; polyfill(pts, 4, CLR_BLUE);' },
  thickline:  { sig: 'void thickline(int x1, int y1, int x2, int y2, int w, int color)', doc: 'Line with pixel width w. Round caps at both ends. w=1 behaves like line().\nthickline(10, 10, 90, 50, 4, CLR_RED);' },
  thicklineoutline: { sig: 'void thicklineoutline(int x1, int y1, int x2, int y2, int w, int color)', doc: 'Outline of a thick line — the capsule (stadium) border. Hugs thickline() exactly; draw over a thickline fill for a bordered cable.\nthicklineoutline(10, 10, 90, 50, 8, CLR_WHITE);' },
  rrect:      { sig: 'void rrect(int x, int y, int w, int h, int r, int color)',      doc: 'Rounded rectangle outline. r = corner radius in pixels.\nrrect(10, 10, 80, 40, 6, CLR_WHITE);' },
  rrectfill:  { sig: 'void rrectfill(int x, int y, int w, int h, int r, int color)', doc: 'Filled rounded rectangle. Panels, buttons, speech bubbles.\nrrectfill(10, 10, 80, 40, 6, CLR_DARK_BLUE);' },
  gradient:   { sig: 'void gradient(int x, int y, int w, int h, int c_a, int c_b, float angle_deg)', doc: 'Dithered gradient at any angle inside a rect. 0 = left→right, 90 = top→bottom, 45 = diagonal. c_a is the color at the start of the direction, c_b at the end.\ngradient(0, 0, SCREEN_W, SCREEN_H, CLR_DARK_BLUE, CLR_BLACK, 45);' },
  vgradient:  { sig: 'void vgradient(int x, int y, int w, int h, int c_top, int c_bot)',    doc: 'Vertical dithered gradient from c_top to c_bot. Replaces stacks of rectfill for skies and backdrops.\nvgradient(0, 0, SCREEN_W, SCREEN_H, CLR_DARK_BLUE, CLR_BLACK);' },
  hgradient:  { sig: 'void hgradient(int x, int y, int w, int h, int c_left, int c_right)', doc: 'Horizontal dithered gradient from c_left to c_right. Side lighting, panels.\nhgradient(0, 0, SCREEN_W, 20, CLR_DARK_GREY, CLR_BLACK);' },

  // ── c basics ── (kind: 'keyword' = skipped by autocomplete, but still used for hover tooltips and the help tab)
  include:    { kind: 'keyword', sig: '#include "studio.h"',                            doc: 'Pulls in declarations from another file. #include "studio.h" gives you every dreamengine function and constant.' },
  define:     { kind: 'keyword', sig: '#define NAME 42',                                doc: 'Gives a value a name. Used for constants like screen size or button IDs. No semicolon at the end.' },
  int:        { kind: 'keyword', sig: 'int x = 5;',                                     doc: 'A whole number, no decimals. Can be negative. Math like + - * / % all work on it.' },
  float:      { kind: 'keyword', sig: 'float p = 0.5f;',                                doc: 'A number with decimals. Use the f suffix on literals: 1.5f, not 1.5.' },
  bool:       { kind: 'keyword', sig: 'bool ok = true;',                                doc: 'True or false, nothing else. Used for flags and conditions.' },
  void:       { kind: 'keyword', sig: 'void update() { ... }',                          doc: '"Nothing." A function declared void runs but doesn\'t hand back a value.' },
  if:         { kind: 'keyword', sig: 'if (x > 10) { ... } else { ... }',               doc: 'Run the block only when the condition is true. Pair with else for the "otherwise" branch.' },
  for:        { kind: 'keyword', sig: 'for (int i = 0; i < 10; i++) { ... }',           doc: 'Counted loop. Three parts inside the parens: starting value, condition to keep going, step at the end of each pass.' },
  return:     { kind: 'keyword', sig: 'return 42;',                                     doc: 'Leave the current function. If the function has a return type, the value follows.' },
  logical:    { kind: 'keyword', sig: 'if (a && !b) { ... }',                           doc: 'Logical operators: && (and) needs both true; || (or) needs at least one; ! flips true and false.' },
  equality:   { kind: 'keyword', sig: 'if (x == 5)   vs   x = 5;',                      doc: 'One = assigns: x = 5 puts 5 into x. Two == compares: x == 5 asks "is x equal to 5?". Mistaking the two is one of the most common bugs in C.' },
  comment:    { kind: 'keyword', sig: '// this is ignored',                             doc: 'A comment. Everything from // to the end of the line is for humans only — the compiler skips it.' },
  braces:     { kind: 'keyword', sig: '{ ... }',                                        doc: 'Curly braces group statements into a block. Functions, if, for, while all use them.' },
  semicolon:  { kind: 'keyword', sig: 'x = 5;',                                         doc: 'Every statement ends with one. If your code doesn\'t compile, a missing ; is suspect #1.' },
  array:      { kind: 'keyword', sig: 'int a[] = { 1, 2, 3 };',                         doc: 'A fixed-length list of values of the same type. Access elements with a[0], a[1], a[2]. The size is set when you create it.' },
  static:     { kind: 'keyword', sig: 'static int counter = 0;',                        doc: 'Two uses. Inside a function: the variable keeps its value across calls — perfect for a frame counter that survives between update()s without being a global. At file scope: makes a variable or function private to this file.' },
}
